-- Name: audit_table(regclass, boolean, boolean, text[], text, text, text); Type: FUNCTION; Schema: audit; Owner: adc
--

CREATE FUNCTION audit.audit_table(target_table regclass, audit_rows boolean, audit_query_text boolean, ignored_cols text[], audit_if_field_not_null text, audit_if_query_exists text, audit_if_query_exists_placeholder_field text) RETURNS void
    LANGUAGE plpgsql
    AS $_$ 
			DECLARE
			stm_targets text = 'INSERT OR UPDATE OR DELETE OR TRUNCATE';
			_q_txt text;
			_parameter text;
			BEGIN
				EXECUTE 'DROP TRIGGER IF EXISTS audit_trigger_row ON ' || quote_ident(target_table::text);
				EXECUTE 'DROP TRIGGER IF EXISTS audit_trigger_stm ON ' || quote_ident(target_table::text);

				_parameter = quote_literal(audit_query_text);
				IF audit_rows THEN
					_parameter = _parameter || ', ';
					IF array_length(ignored_cols,1) > 0 THEN
						_parameter = _parameter || quote_literal(ignored_cols);
					ELSE
						_parameter = _parameter || quote_literal('');
					END IF;
					_parameter = _parameter || ', ';
					IF length(audit_if_field_not_null) > 0 THEN
						_parameter = _parameter || quote_literal(audit_if_field_not_null);
					ELSE
						_parameter = _parameter || quote_literal('');
					END IF;
					_parameter = _parameter || ', ';
					IF length(audit_if_query_exists) > 0 THEN
						_parameter = _parameter || quote_literal(audit_if_query_exists);
					ELSE
						_parameter = _parameter || quote_literal('');
					END IF;
					_parameter = _parameter || ', ';
					IF length(audit_if_query_exists_placeholder_field) > 0 THEN
						_parameter = _parameter || quote_literal(audit_if_query_exists_placeholder_field);
					ELSE
						_parameter = _parameter || quote_literal('');
					END IF;

					_q_txt = 'CREATE TRIGGER audit_trigger_row AFTER INSERT OR UPDATE OR DELETE ON ' ||
							quote_ident(target_table::text) ||
							' FOR EACH ROW
							WHEN (public.sv_current_setting($$softwarevision.disableaudit$$, $$false$$) = $$false$$)
							EXECUTE PROCEDURE audit.if_modified_func('
							|| _parameter || ');';
					EXECUTE _q_txt;
					stm_targets = 'TRUNCATE';
				ELSE
				END IF;

				_q_txt = 'CREATE TRIGGER audit_trigger_stm AFTER ' || stm_targets || ' ON ' ||
						target_table ||
						' FOR EACH STATEMENT
						WHEN (public.sv_current_setting($$softwarevision.disableaudit$$, $$false$$) = $$false$$)
						EXECUTE PROCEDURE audit.if_modified_func('||
						quote_literal(audit_query_text) || ');';
				EXECUTE _q_txt;
			END;
		 $_$;


ALTER FUNCTION audit.audit_table(target_table regclass, audit_rows boolean, audit_query_text boolean, ignored_cols text[], audit_if_field_not_null text, audit_if_query_exists text, audit_if_query_exists_placeholder_field text) OWNER TO adc;

--
-- Name: if_modified_func(); Type: FUNCTION; Schema: audit; Owner: adc
--

CREATE FUNCTION audit.if_modified_func() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			DECLARE
				audit_row audit.logged_actions;
				include_values boolean;
				log_diffs boolean;
				h_old hstore;
				h_new hstore;
				excluded_cols text[] = ARRAY[]::text[];
				audit_if_field_not_null text;
				audit_if_field_not_null_value text;
				audit_if_query_exists text;
				audit_if_query_exists_placeholder_field text;
				audit_if_query_exists_placeholder_value text;
				audit_if_query_exists_count integer;
				audit_if_disable_temporary integer;
			BEGIN
				IF TG_WHEN <> 'AFTER' THEN
					RAISE EXCEPTION 'audit.if_modified_func() may only run as an AFTER trigger';
				END IF;

				audit_row = ROW(
					nextval('audit.logged_actions_event_id_seq'), -- event_id
					TG_TABLE_SCHEMA::text,                        -- schema_name
					TG_TABLE_NAME::text,                          -- table_name
					TG_RELID,                                     -- relation OID for much quicker searches
					session_user::text,                           -- session_user_name
					current_timestamp,                            -- action_tstamp_tx
					statement_timestamp(),                        -- action_tstamp_stm
					clock_timestamp(),                            -- action_tstamp_clk
					txid_current(),                               -- transaction ID
					current_setting('application_name'),          -- client application
					inet_client_addr(),                           -- client_addr
					inet_client_port(),                           -- client_port
					current_query(),                              -- top-level query or queries (if multistatement) from client
					substring(TG_OP,1,1),                         -- action
					NULL, NULL,                                   -- row_data, changed_fields
					'f',                                          -- statement_only
					public.sv_current_setting('softwarevision.currentuser') -- current user id (public.personen.id)
					);

				IF NOT TG_ARGV[0]::boolean IS DISTINCT FROM 'f'::boolean THEN
					audit_row.client_query = NULL;
				END IF;

				IF length(TG_ARGV[1]::text) > 0 THEN
					excluded_cols = TG_ARGV[1]::text[];
				END IF;

				excluded_cols = excluded_cols || ARRAY['updated_at'];

				IF TG_LEVEL = 'ROW' AND (length(TG_ARGV[2]::text) > 0 OR length(TG_ARGV[3]::text) > 0) THEN
					IF length(TG_ARGV[2]::text) > 0 THEN
						audit_if_field_not_null = TG_ARGV[2]::text;

						IF (TG_OP = 'DELETE') THEN
							IF (hstore(OLD.*) -> audit_if_field_not_null) IS NULL THEN
								RETURN NULL;
							END IF;
						ELSIF (TG_OP = 'UPDATE') THEN
							IF ((hstore(OLD.*) -> audit_if_field_not_null) IS NULL
								AND (hstore(NEW.*) -> audit_if_field_not_null) IS NULL) THEN
								RETURN NULL;
							END IF;
						ELSIF (TG_OP = 'INSERT') THEN
							IF (hstore(NEW.*) -> audit_if_field_not_null) IS NULL THEN
								RETURN NULL;
							END IF;
						END IF;

					END IF;

					IF length(TG_ARGV[3]::text) > 0 THEN
						audit_if_query_exists = TG_ARGV[3]::text;
						audit_if_query_exists_placeholder_field = TG_ARGV[4]::text;

						IF (TG_OP = 'DELETE') THEN
							audit_if_query_exists_placeholder_value = hstore(OLD.*) -> audit_if_query_exists_placeholder_field;
						ELSIF (TG_OP = 'UPDATE' OR TG_OP = 'INSERT') THEN
							audit_if_query_exists_placeholder_value = hstore(NEW.*) -> audit_if_query_exists_placeholder_field;
						END IF;

						IF (audit_if_query_exists_placeholder_value IS NULL) THEN
							RETURN NULL;
						END IF;

						EXECUTE format(audit_if_query_exists, audit_if_query_exists_placeholder_value);
						GET DIAGNOSTICS audit_if_query_exists_count = ROW_COUNT;

						IF (audit_if_query_exists_count = 0) THEN
							RETURN NULL;
						END IF;
					END IF;
				END IF;

				IF (TG_OP = 'UPDATE' AND TG_LEVEL = 'ROW') THEN
					audit_row.row_data = hstore(OLD.*) - excluded_cols;
					audit_row.changed_fields =  (hstore(NEW.*) - audit_row.row_data) - excluded_cols;
					IF audit_row.changed_fields = hstore('') THEN
						-- All changed fields are ignored. Skip this update.
						RETURN NULL;
					END IF;
				ELSIF (TG_OP = 'DELETE' AND TG_LEVEL = 'ROW') THEN
					audit_row.row_data = hstore(OLD.*) - excluded_cols;
				ELSIF (TG_OP = 'INSERT' AND TG_LEVEL = 'ROW') THEN
					audit_row.row_data = hstore(NEW.*) - excluded_cols;
				ELSIF (TG_LEVEL = 'STATEMENT' AND TG_OP IN ('INSERT','UPDATE','DELETE','TRUNCATE')) THEN
					audit_row.statement_only = 't';
				ELSE
					RAISE EXCEPTION '[audit.if_modified_func] - Trigger func added as trigger for unhandled case: %, %',TG_OP, TG_LEVEL;
					RETURN NULL;
				END IF;
				INSERT INTO audit.logged_actions VALUES (audit_row.*);
				RETURN NULL;
			END;
		 $$;


ALTER FUNCTION audit.if_modified_func() OWNER TO adc;

