--
-- Name: add_business_days(date, integer); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.add_business_days(startdate date, days integer) RETURNS date
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				_result date;
				_offset CONSTANT integer = CASE WHEN extract('isodow' from startdate) BETWEEN 1 AND 5 THEN abs(days) ELSE abs(days)-1 END;
			BEGIN
				WITH tbl_alldates AS (
					SELECT diff, startdate + (diff * CASE WHEN days < 0 THEN -1 ELSE 1 END) AS date

					-- NOTE we add 5 and x 2, to make sure the sequence has enough in it to cope with weekends/holidays that get omitted later
					FROM generate_series(0, (abs(days) + 5)*2) diff
				),
				tbl_days AS (
					SELECT diff, date, extract('isodow' FROM date) AS dow
					FROM tbl_alldates
				),
				tbl_businessdays AS (
					SELECT diff, date, d.dow FROM tbl_days d
				--	LEFT JOIN holidays h ON d.date = h.date AND h.country = land AND h.subdiv = bundesland
				--	WHERE h.date IS NULL
					WHERE d.dow BETWEEN 1 AND 5
					ORDER BY diff
				)
				SELECT date FROM tbl_businessdays
				WHERE CASE WHEN days > 0 THEN date >= startdate WHEN days < 0 THEN date <= startdate ELSE date = startdate END
				LIMIT 1
				OFFSET _offset
				INTO _result;

				RETURN _result;
			END
		 $$;


ALTER FUNCTION public.add_business_days(startdate date, days integer) OWNER TO adc;

--
-- Name: add_business_days(timestamp without time zone, integer); Type: FUNCTION; Schema: public; Owner: adc
