--
-- Name: add_business_days_sepa(date, integer); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.add_business_days_sepa(startdate date, days integer) RETURNS date
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				_result date;
				_offset CONSTANT integer = CASE WHEN extract('isodow' from startdate) BETWEEN 1 AND 5 THEN abs(days) ELSE abs(days)-1 END;
				_startyear CONSTANT integer = extract('year' FROM startdate)::integer;
			BEGIN
				WITH tbl_alldates AS (
					SELECT diff, startdate + (diff * CASE WHEN days < 0 THEN -1 ELSE 1 END) AS date

					-- NOTE we add 5 and x 2, to make sure the sequence has enough in it to cope with weekends/holidays that get omitted later
					FROM generate_series(0, (abs(days) + 5)*2) diff
				),
				tbl_days AS (
					SELECT diff, date, extract('isodow' FROM date) AS dow
					FROM tbl_alldates
				),
				tbl_businessdays AS (
					SELECT diff, date, d.dow FROM tbl_days d
				--	LEFT JOIN holidays h ON d.date = h.date AND h.country = land AND h.subdiv = bundesland
				--	WHERE h.date IS NULL
					WHERE d.dow BETWEEN 1 AND 5
					AND NOT EXISTS (SELECT 1 FROM public.targetFeiertage(_startyear-1, _startyear+1) WHERE targetFeiertage = d.date)
					ORDER BY diff
				)
				SELECT date FROM tbl_businessdays
				WHERE CASE WHEN days > 0 THEN date >= startdate WHEN days < 0 THEN date <= startdate ELSE date = startdate END
				LIMIT 1
				OFFSET _offset
				INTO _result;

				RETURN _result;
			END
		 $$;


ALTER FUNCTION public.add_business_days_sepa(startdate date, days integer) OWNER TO adc;

--
-- Name: add_to_searchlist(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.add_to_searchlist(kunde_ integer, filiale_ integer) RETURNS void
    LANGUAGE plpgsql
    AS $$ 
			BEGIN
				DELETE FROM public.searchlist WHERE kdid = kunde_ AND filiale = filiale_;

				INSERT INTO public.searchlist VALUES(kunde_, NOW(), filiale_);

				DELETE FROM public.searchlist sl WHERE kdid NOT IN (
					SELECT sl.kdid FROM public.searchlist sl
					WHERE sl.filiale = filiale_
					ORDER BY ts DESC LIMIT 100
				)
				AND sl.filiale = filiale_;
			END
		 $$;


ALTER FUNCTION public.add_to_searchlist(kunde_ integer, filiale_ integer) OWNER TO postgres;

--
-- Name: aosync_kunden_fix_mapping(integer, integer); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.aosync_kunden_fix_mapping(_param_eo_kdnr integer, _param_ao_kdnr integer) RETURNS text
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				_ao_kunde integer;
				_del_kunde integer;
				_target_guid_active uuid;
				_target_guid_inactive uuid;
				_target_ao_id_inactive integer;
			BEGIN
				SELECT guid, ao_kunde, del_kunde FROM aosync.kunden k WHERE EXISTS (SELECT 1 FROM aosync.ao_kunden WHERE id = k.ao_kunde AND ao_kdnr = _param_ao_kdnr)
				 INTO _target_guid_active, _ao_kunde, _del_kunde;
				 IF (_del_kunde IS NULL) THEN
					RETURN 'Keinen gelöschten EO-Kunden zur AO-Kundennummer gefunden';
				 END IF;
				 IF (_target_guid_active IS NULL) THEN
					RETURN 'Fehler beim Ermitteln der Ziel-GKuID';
				 END IF;
				 SELECT guid, ao_kunde FROM aosync.kunden WHERE eo_kunde = _param_eo_kdnr
				 INTO _target_guid_inactive, _target_ao_id_inactive;
				 IF (_target_guid_inactive IS NULL) THEN
					RETURN 'Fehler beim Ermitteln der alten GKuID';
				 END IF;
				 -- Ziel-GUID / ao_kunde für nicht gelöschten Kunden verfügbar machen
				 UPDATE aosync.kunden SET guid = uuid_generate_v1(), ao_kunde = null
				 WHERE del_kunde = _del_kunde;
				 -- Ziel-GUID und -AO -Kunde in aktiven Kunden schreiben
				 UPDATE aosync.kunden SET guid = _target_guid_active, ao_kunde = _ao_kunde, last_update = now()
				 WHERE eo_kunde = _param_eo_kdnr;
				 -- alte GUID und inaktiven AO-Kunden inaktivem EO-Kunden zuordnen
				 UPDATE aosync.kunden SET guid = _target_guid_inactive, ao_kunde = _target_ao_id_inactive, last_update = now()
				 WHERE del_kunde = _del_kunde;
				 RETURN 'OK';
			END;
		 $$;


ALTER FUNCTION public.aosync_kunden_fix_mapping(_param_eo_kdnr integer, _param_ao_kdnr integer) OWNER TO adc;

--
-- Name: bestellung_glas_update_fortlaufende_nummer(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.bestellung_glas_update_fortlaufende_nummer() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			BEGIN
				IF (public.sv_current_setting('softwarevision.disable_bestellung_glas_update_fortlaufende_nummer', 'false') = 'true') THEN
					RETURN NEW;
				END IF;
				SELECT COUNT(*) + 1 INTO NEW.fortlaufende_nummer FROM public.bestellung_glas WHERE auftrag = NEW.auftrag AND auftragsart = NEW.auftragsart;
				RETURN NEW;
			END;
		 $$;


ALTER FUNCTION public.bestellung_glas_update_fortlaufende_nummer() OWNER TO adc;

--
-- Name: brauftrag_update_preissonst(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.brauftrag_update_preissonst() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				auftragid integer;
			BEGIN
				IF (TG_OP = 'DELETE') THEN
					auftragid = OLD.auftrag;
				ELSE
					auftragid = NEW.auftrag;
				END IF;
				UPDATE public.brauftrag SET preis_sonst = (SELECT SUM(numericempty(preis)) FROM public.brsonst WHERE auftrag = auftragid GROUP BY auftrag) WHERE id = auftragid;
				RETURN NULL;
			END;
		 $$;


ALTER FUNCTION public.brauftrag_update_preissonst() OWNER TO adc;

--
-- Name: brauftrag_update_price(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.brauftrag_update_price() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$ 
			DECLARE
				mwstsatz double precision = 0;
				mwstsatz_versicherung double precision = 0;
				mwst numeric = 0;
				mwstsonst numeric = 0;
				rabattfactor double precision = 0;
			BEGIN
				CASE NEW.netto
				WHEN 2 THEN --Netto
						CASE NEW.mwst
						WHEN 0 THEN --Mehrwertsteuer::MwStNormal
							mwstsatz = NEW.mwstsatz0;
						WHEN 1 THEN --Mehrwertsteuer::MwStErmaessigt
							mwstsatz = NEW.mwstsatz1;
						ELSE
							mwstsatz = 0;
						END CASE;

						CASE NEW.versicherung_mwsttyp
						WHEN 0 THEN --Mehrwertsteuer::MwStNormal
							mwstsatz_versicherung = NEW.mwstsatz0;
						WHEN 1 THEN --Mehrwertsteuer::MwStErmaessigt
							mwstsatz_versicherung = NEW.mwstsatz1;
						ELSE
							mwstsatz_versicherung = 0;
						END CASE;

					mwst = (numericempty(NEW.fassung_preis) + numericempty(NEW.glasre_preis) + numericempty(NEW.glasli_preis)
								 - numericempty(NEW.preis_kk) ) * (mwstsatz / 100);
					mwst = mwst + (numericempty(NEW.versicherung_preis) * (mwstsatz_versicherung / 100) );
					-- Mwst für Sonstpositionen ausrechnen
					EXECUTE 'SELECT SUM('
							'				('
							'					numericempty(preis)'
							'					* ('
							'						CASE WHEN mwst_typ = 0 THEN'
							'							$1'
							'						WHEN mwst_typ = 1 THEN'
							'							$2'
							'						ELSE 0 END / 100'
							'					)'
							'				)'
							'			)'
							' FROM brsonst'
							' WHERE auftrag = $3'
							' GROUP BY auftrag'
						INTO mwstsonst USING NEW.mwstsatz0, NEW.mwstsatz1, NEW.id;
					-- Rabattfaktor berechnen
					rabattfactor = ( numericempty(NEW.fassung_preis) + numericempty(NEW.glasre_preis)
									+ numericempty(NEW.glasli_preis) + numericempty(NEW.versicherung_preis)
									+ numericempty(NEW.preis_sonst) - numericempty(NEW.preis_kk)
									- numericempty(NEW.rabatt) )
									/
									( numericempty(NEW.fassung_preis) + numericempty(NEW.glasre_preis)
									+ numericempty(NEW.glasli_preis) + numericempty(NEW.versicherung_preis)
									+ numericempty(NEW.preis_sonst) - numericempty(NEW.preis_kk) );
					NEW.preis = numericempty(NEW.fassung_preis) + numericempty(NEW.glasre_preis) + numericempty(NEW.glasli_preis)
								+ numericempty(NEW.preis_sonst) + numericempty(NEW.versicherung_preis)
								+ (usezerofornull(mwstsonst) + usezerofornull(mwst)) * rabattfactor;
				ELSE
					NEW.preis = numericempty(NEW.fassung_preis) + numericempty(NEW.glasre_preis) + numericempty(NEW.glasli_preis)
								+ numericempty(NEW.preis_sonst) + numericempty(NEW.versicherung_preis);
				END CASE;

				RETURN NEW;
			END;
		 $_$;


ALTER FUNCTION public.brauftrag_update_price() OWNER TO adc;

--
-- Name: check_fkey(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.check_fkey() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$ 
			DECLARE
				column_name text := TG_ARGV[0];
				ref_schema text := TG_ARGV[1];
				ref_table text := TG_ARGV[2];
				ref_column text := TG_ARGV[3];
				id integer;
				ref_row_count integer;
			BEGIN
				IF TG_NARGS != 4 THEN
					RAISE EXCEPTION 'Trigger "%" of table "%" has % arguments (required: 4)', TG_NAME, TG_RELNAME, TG_NARGS;
				END IF;

				-- Einzufügende Id in 'id' speichern
				EXECUTE 'SELECT $1.'||quote_ident(column_name) INTO id USING NEW;
				-- Wenn der Wert NULL is verlassen wir uns auf ein evtl. vorhandenes NOT-NULL Constraint.
				IF id IS NULL THEN
					RETURN NEW;
				END IF;

				EXECUTE 'SELECT '||quote_ident(ref_column)||' FROM '||ref_schema||'.'||ref_table||' WHERE '||quote_ident(ref_column)||' = $1' USING id;
				GET DIAGNOSTICS ref_row_count = ROW_COUNT;
				IF ref_row_count != 1 THEN
					RAISE foreign_key_violation
						USING MESSAGE = 'insert or update on table "'||TG_RELNAME||'" violates foreign key constraint',
						DETAIL = 'Key ('||column_name||')=('||id||') is not present in '||ref_schema||'.'||ref_table||'.'||ref_column;
				END IF;

				RETURN NEW;
			END
		 $_$;


ALTER FUNCTION public.check_fkey() OWNER TO adc;

--
-- Name: createrechnungsnummer(integer, boolean); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.createrechnungsnummer(filiale_ integer, is_kk_ boolean) RETURNS text
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				_nextval_nr int;
				_found_nv boolean;
				_rechnung_nr text;
				_nextval_tabelle text;
			BEGIN
				IF is_kk_ THEN
					_nextval_tabelle := 'abrechnung';
				ELSE
					_nextval_tabelle := 'rechnung';
				END IF;
				_found_nv := FALSE;
				SELECT nr INTO _nextval_nr FROM public.nextval WHERE tabelle = _nextval_tabelle AND feld = filiale_::text FOR UPDATE;
				IF FOUND THEN
					_found_nv := TRUE;
				END IF;
				IF _nextval_nr IS NULL THEN
					_nextval_nr := 10000;
				END IF;
				--RAISE NOTICE 'found_nv % nextval_nr %', _found_nv, _nextval_nr;
				IF _found_nv THEN
					UPDATE public.nextval SET nr = _nextval_nr + 1 WHERE tabelle = _nextval_tabelle AND feld = filiale_::text;
				ELSE
					INSERT INTO public.nextval(nr, tabelle, feld) VALUES(_nextval_nr + 1, _nextval_tabelle, filiale_::text);
				END IF;
				IF filiale_ = 0 THEN
					_rechnung_nr := _nextval_nr::text;
				ELSE
					_rechnung_nr := filiale_::text || '-' || _nextval_nr::text;
				END IF;
				IF is_kk_ THEN
					_rechnung_nr := 'KK' || _rechnung_nr;
				END IF;
				RETURN _rechnung_nr;
			 END;
		 $$;


ALTER FUNCTION public.createrechnungsnummer(filiale_ integer, is_kk_ boolean) OWNER TO adc;

--
-- Name: doppellaute(text); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.doppellaute(text) RETURNS text
    LANGUAGE plpgsql STRICT
    AS $_$ 
			DECLARE
				sResult text;
			BEGIN
				sResult := UPPER($1);
				sResult := REGEXP_REPLACE( sResult, '[\xC0\xC1\xC2\xC3\xC5]', 'A', 'g' );
				sResult := REGEXP_REPLACE( sResult, '[Ä\xC6]', 'AE', 'g' );
				sResult := REGEXP_REPLACE( sResult, '[\xC8\xC9\xCA\xCB]', 'E', 'g' );
				sResult := REGEXP_REPLACE( sResult, '[\xCC\xCD\xCE\xCF]', 'I', 'g' );
				sResult := REGEXP_REPLACE( sResult, '[\xD2\xD3\xD4\xD5\xD8]', 'O', 'g' );
				sResult := REPLACE( sResult, 'Ö', 'OE' );
				sResult := REGEXP_REPLACE( sResult, '[\xD9\xDA\xDB]', 'U', 'g' );
				sResult := REPLACE( sResult, 'Ü', 'UE' );
				sResult := REPLACE( sResult, 'ß', 'SS' );
				RETURN sResult;
			END;
		 $_$;


ALTER FUNCTION public.doppellaute(text) OWNER TO adc;

--
-- Name: eastersunday(integer); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.eastersunday(year integer) RETURNS date
    LANGUAGE plpgsql
    AS $_$ 
			DECLARE
				a	integer;
				b	integer;
				c	integer;
				d	integer;
				e	integer;
				f	integer;
				g	integer;
				h	integer;
				i	integer;
				k	integer;
				l	integer;
				m	integer;
				n	integer;
				p	integer;

			BEGIN
				a := $1 % 19;
				b := $1 / 100;
				c := $1 % 100;

				d := b / 4;
				e := b % 4;

				f := (b + 8) / 25;
				g := (b - f + 1) / 3;

				h := (19 * a + b - d - g + 15) % 30;

				i := c / 4;
				k := c % 4;

				l := (32 + 2 * e + 2 * i - h - k) % 7;

				m := (a + 11 * h + 22 * l) / 451;

				n := (h + l - 7 * m + 114) / 31;
				p := (h + l - 7 * m + 114) % 31;

				return to_date($1 || '-' || n || '-' || p+1, 'yyyy-mm-dd');
			END
		 $_$;


ALTER FUNCTION public.eastersunday(year integer) OWNER TO adc;

--
-- Name: fassung_inventur(date); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.fassung_inventur(date) RETURNS TABLE(id integer, modell integer, farbe text, groesse text, buegellaenge integer, aufgenommen_am date, verkauft_am date, verkauft_auftrag integer, ekpreis numeric, vkpreis numeric, abschreibung_mon integer, rabatt numeric, skonto numeric, geloescht_datum date, geloescht_grund integer, artikelnummer_lieferant text, charge text, sonnenbrille boolean, letzterwert numeric, inventurwert numeric, lager integer, isgezaehlt boolean, iskommission boolean, sent_datum timestamp without time zone, move_historie integer, ismusterfassung boolean)
    LANGUAGE sql
    AS $_$ 
			SELECT f.id, f.modell, f.farbe, f.groesse, f.buegellaenge, f.aufgenommen_am, f.verkauft_am,
					f.verkauft_auftrag, f.ekpreis, f.vkpreis, f.abschreibung_mon, f.rabatt, f.skonto,
					f.geloescht_datum, f.geloescht_grund, f.artikelnummer_lieferant, f.charge,
					f.sonnenbrille,
					CASE WHEN h.id IS NOT NULL THEN h.sent_letzterwert ELSE f.letzterwert END,
					CASE WHEN h.id IS NOT NULL THEN h.sent_inventurwert ELSE f.inventurwert END,
					CASE WHEN h.sent_datum::date = $1 THEN h.received_filiale WHEN h.sent_datum::date > $1 THEN h.sent_filiale ELSE f.lager END,
					--FASSUNG_FLG_INVENTUR
					CASE WHEN h.id IS NOT NULL THEN true ELSE (f.flags & 2) > 0 END,
					--FASSUNG_FLG_KOMMISSIONSWARE
					(f.flags & 8) > 0,
					CASE WHEN h.id IS NOT NULL THEN h.sent_datum END,
					h.id,
					--FASSUNG_FLG_MUSTER 0x200
					(f.flags & 512) > 0
				FROM public.fassung f
				LEFT JOIN (SELECT DISTINCT ON (fassung) * FROM public.fassung_move_historie WHERE sent_datum::date >= $1 ORDER BY fassung,sent_datum ASC) AS h ON h.fassung = f.id
				 $_$;


ALTER FUNCTION public.fassung_inventur(date) OWNER TO adc;

--
-- Name: geplante_zahlung_update_preisoffen_anzahlung(integer[]); Type: FUNCTION; Schema: public; Owner: admin
--

CREATE FUNCTION public.geplante_zahlung_update_preisoffen_anzahlung(_param_array_geplante_zahlung_id integer[]) RETURNS void
    LANGUAGE sql
    AS $$ 
			WITH _zahlungen_geplant AS (
				SELECT zp.id, SUM(COALESCE(zl.betrag, 0)) AS gezahlt, zp.betrag-SUM(COALESCE(zl.betrag, 0)) AS offen
				FROM rechnung_zahlung_geplant zp
				LEFT JOIN rechnung_zahlung_geleistet zl ON zl.parent = zp.id AND zl.deleted_datum IS NULL
				WHERE zp.id IN (SELECT(UNNEST(_param_array_geplante_zahlung_id)))
				GROUP BY zp.id
			)

			UPDATE public.rechnung_zahlung_geplant zg SET update_anzahlung_preisoffen_dirty = false, offen = _czg.offen, gezahlt = _czg.gezahlt
			FROM _zahlungen_geplant _czg WHERE _czg.id = zg.id;
		 $$;


ALTER FUNCTION public.geplante_zahlung_update_preisoffen_anzahlung(_param_array_geplante_zahlung_id integer[]) OWNER TO admin;

