--
-- Name: get_anschreiben_vorlauf(public.anschreiben, public.kunden, public.clleasinggruppe); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.get_anschreiben_vorlauf(ansch public.anschreiben, kd public.kunden, clsystem public.clleasinggruppe) RETURNS interval
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				praef_sms CONSTANT integer := 3;	-- KOMMPRAEF_SMS
				praef_email CONSTANT integer := 2;	-- KOMMPRAEF_EMAIL
			BEGIN
				CASE
				WHEN ansch.typ_id IS NULL THEN
					RETURN INTERVAL '1 week';

				WHEN ansch.typ_id = 100001		-- ANSCHREIBEN_CL_PFLEGEMITTEL
				  OR ansch.typ_id = 100002		-- ANSCHREIBEN_CL_PFLEGEMITTEL_ABO
				  OR ansch.typ_id = 100003		-- ANSCHREIBEN_CL_PFLEGEMITTEL_CCC
				  OR ansch.typ_id = 100011		-- ANSCHREIBEN_CL_LINSENTAUSCH
				  OR ansch.typ_id = 100021		-- ANSCHREIBEN_CL_UEBERPRUEFUNG
				  OR ansch.typ_id = 100022		-- ANSCHREIBEN_CL_UEBERPRUEFUNG_ABO
				  OR ansch.typ_id = 100023		-- ANSCHREIBEN_CL_UEBERPRUEFUNG_CCC
				  OR ansch.typ_id = 100024 THEN -- ANSCHREIBEN_SEPA_VORABANKUENDIGUNG
					IF kd.praeferenz = praef_sms AND ansch.use_sms AND char_length(kd.mobil) > 0 THEN
						RETURN INTERVAL '1 day' * ansch.vorlaufzeit_sms;
					ELSEIF kd.praeferenz = praef_email AND ansch.use_email AND char_length(kd.email) > 0 THEN
						RETURN INTERVAL '1 day' * ansch.vorlaufzeit_email;
					ELSE
						RETURN INTERVAL '1 day' * ansch.vorlaufzeit_brief;
					END IF;
				WHEN ansch.typ_id = 100012 THEN	-- ANSCHREIBEN_CL_LINSENTAUSCH_ABO
					IF kd.praeferenz = praef_sms AND ansch.use_sms AND char_length(kd.mobil) > 0 THEN
						RETURN INTERVAL '1 day' * clsystem.tauschvorlauf_sms_abo;
					ELSEIF kd.praeferenz = praef_email AND ansch.use_email AND char_length(kd.email) > 0 THEN
						RETURN INTERVAL '1 day' * clsystem.tauschvorlauf_email_abo;
					ELSE
						RETURN INTERVAL '1 day' * clsystem.tauschvorlauf_brief_abo;
					END IF;
				WHEN ansch.typ_id = 100013 THEN	-- ANSCHREIBEN_CL_LINSENTAUSCH_CCC
					IF kd.praeferenz = praef_sms AND ansch.use_sms AND char_length(kd.mobil) > 0 THEN
						RETURN INTERVAL '1 day' * clsystem.tauschvorlauf_sms_ccc;
					ELSEIF kd.praeferenz = praef_email AND ansch.use_email AND char_length(kd.email) > 0 THEN
						RETURN INTERVAL '1 day' * clsystem.tauschvorlauf_email_ccc;
					ELSE
						RETURN INTERVAL '1 day' * clsystem.tauschvorlauf_brief_ccc;
					END IF;
				END CASE;
			END;
		 $$;


ALTER FUNCTION public.get_anschreiben_vorlauf(ansch public.anschreiben, kd public.kunden, clsystem public.clleasinggruppe) OWNER TO adc;

