-- Name: intervall2monate(integer); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.intervall2monate(integer) RETURNS integer
    LANGUAGE sql
    AS $_$ 
			SELECT CASE $1
						WHEN 1 THEN	1	-- EODefines::Intervall1Monat
						WHEN 6 THEN	2	-- EODefines::Intervall2Monate
						WHEN 2 THEN	3	-- EODefines::Intervall3Monate
						WHEN 3 THEN	6	-- EODefines::Intervall6Monate
						WHEN 4 THEN	9	-- EODefines::Intervall9Monate
						WHEN 5 THEN	12	-- EODefines::Intervall1Jahr
						WHEN 7 THEN	18	-- EODefines::Intervall18Monate
						WHEN 8 THEN	24	-- EODefines::Intervall2Jahre
						ELSE		0
					END;
		 $_$;


ALTER FUNCTION public.intervall2monate(integer) OWNER TO adc;

--
-- Name: kasse_tagesabschluss_noetig(date, boolean, integer); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.kasse_tagesabschluss_noetig(check_date_ date, ta_am_naechsten_tag_ boolean, filiale_ integer) RETURNS boolean
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				letzter_ta		date;
				juengste_buchung	date;
				naechster_ta		date;
			BEGIN
				-- Datum der jüngsten Buchung ermitteln.
				SELECT INTO juengste_buchung
				(WITH first_dates AS (
					SELECT MIN(datum::date) AS datum FROM public.currentbon WHERE filiale = filiale_
					UNION DISTINCT
					SELECT MIN(dt::date) AS datum  FROM public.bareinlage WHERE filiale = filiale_
					UNION DISTINCT
					SELECT MIN(dt::date) AS datum  FROM public.barentnahme WHERE filiale = filiale_
				)
				SELECT MIN(datum)
				FROM first_dates);

				-- Kein Tagesabschluss nötig, solange die jüngste Buchung heute war (oder gar nicht existiert).
				IF (juengste_buchung IS NULL OR juengste_buchung >= check_date_) THEN
					RETURN false;
				END IF;

				-- Die jüngste Buchung liegt in der Vergangenheit. Prüfen, wenn der letzte Tagesabschluss durchgeführt wurde.
				SELECT INTO letzter_ta
				MAX(datum) FROM public.tagesabschluss WHERE filiale = filiale_;

				-- Der nächste TA wird einen Tag weiter verschoben, wenn die letzte Buchung am selben Tag nach dem TA erzeugt wurde.
				IF (letzter_ta = juengste_buchung) THEN
					naechster_ta := letzter_ta + integer '1';
				ELSE
					naechster_ta := juengste_buchung;
				END IF;

				-- Wenn der nächste TA auf den Sonntag verschoben wurde und an diesem Tag keine Buchung existiert,
				-- wird der nächste TA nochmal auf den Montag verschoben.
				IF (EXTRACT(DOW FROM naechster_ta) = 0) THEN
					IF (EXISTS(SELECT 1 FROM public.currentbon WHERE datum::date = naechster_ta AND filiale = filiale_)
					OR EXISTS(SELECT 1 FROM public.bareinlage WHERE dt::date = naechster_ta AND filiale = filiale_)
					OR EXISTS(SELECT 1 FROM public.barentnahme WHERE dt::date = naechster_ta AND filiale = filiale_)) = false THEN
						naechster_ta := naechster_ta + integer '1';
					END IF;
				END IF;

				-- Wenn ein Tagesabschluss einen Tag später möglich ist, wird dies hier auch noch mit berücksichtigt.
				IF (ta_am_naechsten_tag_) THEN
					naechster_ta := naechster_ta + integer '1';
				END IF;

				RETURN naechster_ta < check_date_;
			END;
		 $$;


ALTER FUNCTION public.kasse_tagesabschluss_noetig(check_date_ date, ta_am_naechsten_tag_ boolean, filiale_ integer) OWNER TO adc;

--
-- Name: kdapp_message_notify(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.kdapp_message_notify() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				_number_unread_messages integer;
			BEGIN
				-- Wie viele eingehende Nachrichten (Type 0 = Nachricht an den Optiker) wurden noch nicht gelesen?
				SELECT COUNT(*)
				FROM public.kdapp_message
				WHERE type = 0 AND read_from_branch_at IS NULL AND is_deleted_from_branch = false
				INTO _number_unread_messages;
				
				PERFORM pg_notify('unread_message_count', _number_unread_messages::text);
				RETURN NULL;
			END
		 $$;


ALTER FUNCTION public.kdapp_message_notify() OWNER TO adc;

--
-- Name: kk_karte_suche_kunden(text, text, date, text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.kk_karte_suche_kunden(vorname_ text, name_ text, gebdat_ date, strasse_ text, hausnummer_ text, plz_ text, ort_ text, versnr_ text) RETURNS TABLE(id integer, titel text, vorname text, gebdat date, name text, strasse text, plz text, ort text, versnr text)
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				match_name_ boolean := false;
				match_vorname_ boolean := false;
				match_adresse_ boolean := false;
				match_versnr_ boolean := false;
				strasse_mit_hausnummer_ text := strasse_mit_hausnummer(strasse_, hausnummer_);
				doppellaute_name_ text := doppellaute(name_);
				doppellaute_vorname_ text := doppellaute(vorname_);
				doppellaute_strasse_ text := doppellaute(strasse_mit_hausnummer_);
				doppellaute_ort_ text := doppellaute(ort_);
				kd record;

			BEGIN
				FOR kd IN
					SELECT k.id, a.titel, k.vorname, k.name, strasse_mit_hausnummer(k.strasse, k.hausnummer) AS strasse, k.plz, k.ort, k.gebdat, k.kk_nr,
						doppellaute(k.name) AS doppellaute_name,
						doppellaute(k.vorname) AS doppellaute_vorname,
						doppellaute(strasse_mit_hausnummer(k.strasse, k.hausnummer)) AS doppellaute_strasse,
						doppellaute(k.ort) AS doppellaute_ort
					FROM public.kunden k
					LEFT JOIN public.anreden a ON a.id = k.anrede
					WHERE (versnr_ IS NOT NULL AND LENGTH(k.kk_nr) > 0 AND k.kk_nr = versnr_)
						OR doppellaute(k.name) = doppellaute_name_
						OR doppellaute(k.vorname) = doppellaute_vorname_
						OR (doppellaute(strasse_mit_hausnummer(k.strasse, k.hausnummer)) = doppellaute_strasse_ AND (doppellaute(k.ort) = doppellaute_ort_ OR plz_ IS NOT NULL AND k.plz = plz_))
				LOOP
					match_name_ := false;
					match_vorname_ := false;
					match_adresse_ := false;
					match_versnr_ := false;

					IF (versnr_ IS NOT NULL AND kd.kk_nr IS NOT NULL AND versnr_ = kd.kk_nr) THEN
						match_versnr_ := true;
					END IF;
					IF (kd.doppellaute_name = doppellaute_name_) THEN
						match_name_ := true;
					END IF;
					IF (kd.doppellaute_vorname = doppellaute_vorname_) THEN
						match_vorname_ := true;
					END IF;
					IF (kd.doppellaute_strasse = doppellaute_strasse_ AND (kd.doppellaute_ort = doppellaute_ort_ OR plz_ IS NOT NULL AND kd.plz = plz_)) THEN
						match_adresse_ := true;
					END IF;

					IF (match_versnr_ OR (match_name_ AND match_vorname_) OR (match_vorname_ AND gebdat_ IS NOT NULL AND kd.gebdat IS NOT NULL AND kd.gebdat = gebdat_) OR (match_vorname_ AND match_adresse_)) THEN
						id := kd.id;
						titel = kd.titel;
						vorname = kd.vorname;
						gebdat = kd.gebdat;
						name = kd.name;
						strasse := kd.strasse;
						plz = kd.plz;
						ort = kd.ort;
						versnr = kd.kk_nr;
						RETURN NEXT;
					END IF;
				END LOOP;
				RETURN;
			END;
		 $$;


ALTER FUNCTION public.kk_karte_suche_kunden(vorname_ text, name_ text, gebdat_ date, strasse_ text, hausnummer_ text, plz_ text, ort_ text, versnr_ text) OWNER TO adc;

--
-- Name: kunden_insert_aosync_kunden(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.kunden_insert_aosync_kunden() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				_aosync_active boolean;
				_guid uuid;
				_max_last_changed timestamp;
			BEGIN
				SELECT COUNT(id) = 1 FROM public.config WHERE id = 'akuwin_sync_enabled' AND param = 'true' INTO _aosync_active;
				IF (_aosync_active = FALSE) THEN
					RETURN NEW;
				END IF;
				IF (NEW.sync_stamm_last_changed > NEW.sync_eo_last_changed) THEN
					_max_last_changed = NEW.sync_stamm_last_changed;
				ELSE
					_max_last_changed = NEW.sync_eo_last_changed;
				END IF;
				_guid = uuid_generate_v1();
				WHILE EXISTS (SELECT 1 FROM aosync.kunden WHERE guid = _guid) LOOP
					_guid = uuid_generate_v1();
				END LOOP;
				INSERT INTO aosync.kunden (kunde_id, eo_kunde, guid, last_update) VALUES (NEW.id, NEW.id, _guid, _max_last_changed);
				RETURN NEW;
			END
		 $$;


ALTER FUNCTION public.kunden_insert_aosync_kunden() OWNER TO adc;

--
-- Name: kunden_move_on_delete(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.kunden_move_on_delete() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			BEGIN
			INSERT INTO public.kunden_deleted (id, created_at, updated_at, filiale, anrede, name, vorname,
				adresszusatz, strasse, public_domain, hausnummer, land, plz, ort, gebdat, telpriv, telgesch, mobil, fax, email, praeferenz,
				konto, blz, bank, kontoinhaber, iban, bic, schweiz_kontotyp, kk_id, kk_nr, kk_bis, kk_risiko, kk_zuzahlungspflichtig,
				arzt, bemerk, bemerk_intern, info_aboselektion,
				werbung_status, werbung_wege, werbung_datum, werbung_quelle, werbung_praeferenz, optoflow_patient_id, billingo_id, kdapp_id,
				frequentlens_updated_at, frequentlens_is_active,
				aktiv, duzen, letzter_geburtstagsbrief, personenkennzeichen, ccc_altkunde, sync_eo_last_changed, sync_stamm_last_changed,
				austria_kk_hauptversicherter, sm_progression, rechnung_per_email, kassenbon_per_email, flag_per_email_gespeichert)
				VALUES (
					OLD.id, OLD.created_at, OLD.updated_at, OLD.filiale, OLD.anrede, OLD.name, OLD.vorname,
					OLD.adresszusatz, OLD.strasse, OLD.public_domain, OLD.hausnummer, OLD.land, OLD.plz, OLD.ort, OLD.gebdat, OLD.telpriv, OLD.telgesch,
					OLD.mobil, OLD.fax, OLD.email, OLD.praeferenz, OLD.konto, OLD.blz, OLD.bank, OLD.kontoinhaber,
					OLD.iban, OLD.bic, OLD.schweiz_kontotyp, OLD.kk_id, OLD.kk_nr, OLD.kk_bis, OLD.kk_risiko, OLD.kk_zuzahlungspflichtig,
					OLD.arzt, OLD.bemerk, OLD.bemerk_intern, OLD.info_aboselektion,
					OLD.werbung_status, OLD.werbung_wege, OLD.werbung_datum, OLD.werbung_quelle, OLD.werbung_praeferenz, OLD.optoflow_patient_id, OLD.billingo_id, OLD.kdapp_id,
					OLD.frequentlens_updated_at, OLD.frequentlens_is_active,
					OLD.aktiv, OLD.duzen, OLD.letzter_geburtstagsbrief, OLD.personenkennzeichen, OLD.ccc_altkunde, OLD.sync_eo_last_changed, OLD.sync_stamm_last_changed,
					OLD.austria_kk_hauptversicherter, OLD.sm_progression, OLD.rechnung_per_email, OLD.kassenbon_per_email, OLD.flag_per_email_gespeichert
				);

				UPDATE aosync.kunden SET eo_kunde = NULL, del_kunde = OLD.id WHERE kunde_id = OLD.id;
				RETURN OLD;
			END
		 $$;


ALTER FUNCTION public.kunden_move_on_delete() OWNER TO adc;

--
-- Name: kunden_update_eo_last_changed(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.kunden_update_eo_last_changed() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			BEGIN
				IF (NEW.sync_eo_last_changed = OLD.sync_eo_last_changed) THEN
					NEW.sync_eo_last_changed = NOW();
				END IF;
				RETURN NEW;
			END
		 $$;


ALTER FUNCTION public.kunden_update_eo_last_changed() OWNER TO adc;

--
-- Name: kunden_update_max_changed(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.kunden_update_max_changed() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				_max_last_changed timestamp;
			BEGIN
				_max_last_changed = GREATEST(COALESCE(NEW.sync_stamm_last_changed, date '1970-01-01'), COALESCE(NEW.sync_eo_last_changed, date '900-01-01'));
				UPDATE aosync.kunden SET last_update = _max_last_changed WHERE kunde_id = NEW.id AND last_update < _max_last_changed;
				return NEW;
			END
		 $$;


ALTER FUNCTION public.kunden_update_max_changed() OWNER TO adc;

--
-- Name: kunden_update_stamm_last_changed(); Type: FUNCTION; Schema: public; Owner: adc
