CREATE FUNCTION public.kunden_update_stamm_last_changed() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			BEGIN
				IF (NEW.sync_stamm_last_changed = OLD.sync_stamm_last_changed) THEN
					NEW.sync_stamm_last_changed = NOW();
				END IF;
				RETURN NEW;
			END
		 $$;


