--
-- Name: kundenkontakt_notify(); Type: FUNCTION; Schema: public; Owner: admin
--

CREATE FUNCTION public.kundenkontakt_notify() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				_table_available integer;
			BEGIN
			IF (TG_OP = 'INSERT') THEN
				PERFORM pg_notify('kundenkontakt_available', NEW.kunde::text || ',true');
				RETURN NEW;
			END IF;
			IF (TG_OP = 'UPDATE' AND NEW.deleted_at IS NOT NULL) THEN
				SELECT COUNT(*) FROM public.kundenkontakt WHERE kunde = NEW.kunde AND deleted_at IS NULL LIMIT 1 INTO _table_available;
				IF (_table_available = 0) THEN
					PERFORM pg_notify('kundenkontakt_available', NEW.kunde::text || ',false');
				ELSE
					PERFORM pg_notify('kundenkontakt_available', NEW.kunde::text || ',true');
				END IF;
				RETURN NEW;
			END IF;

			RETURN NULL;
			END
		 $$;


ALTER FUNCTION public.kundenkontakt_notify() OWNER TO admin;

--
-- Name: nachrichten_attachments_cleanup(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.nachrichten_attachments_cleanup() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				varSize integer;
				varSha1 text;
			BEGIN
				IF TG_OP = 'UPDATE' AND OLD.size = -1 THEN
					RETURN NULL;
				END IF;
				varSize = OLD.size;
				varSha1 = OLD.sha1;
				DELETE FROM public.nachrichten_attachments_blob WHERE size = varSize AND sha1 = varSha1 AND NOT EXISTS (SELECT 1 FROM public.nachrichten_attachments WHERE size = varSize AND sha1 = varSha1);
				RETURN NULL;
			END;
		 $$;


ALTER FUNCTION public.nachrichten_attachments_cleanup() OWNER TO adc;

