-- Name: numericemptyerror(numeric); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.numericemptyerror(numeric) RETURNS numeric
    LANGUAGE sql
    AS $_$ 
			SELECT COALESCE( NULLIF( NULLIF( $1, -5000 ), -5001 ), 0 );
		 $_$;


