--
-- Name: rechnung_trigger_condition(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.rechnung_trigger_condition(_param_rechnung_id integer) RETURNS boolean
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				_result boolean := True;
				_update_preise_dirty boolean;
			BEGIN
				IF (public.sv_current_setting('softwarevision.disable_rechnung_update_preise', 'false') = 'true') THEN
					RETURN False;
				END IF;
				SELECT public.sv_current_setting('softwarevision.do_rechnung_update_preise', 'false') INTO _update_preise_dirty;
				IF _update_preise_dirty THEN
					_result := False;
				ELSE
					SET softwarevision.do_rechnung_update_preise TO 'true';
				END IF;
				UPDATE public.rechnung SET update_preise_dirty = true WHERE id = _param_rechnung_id AND NOT update_preise_dirty;
				-- RAISE NOTICE 'rechnung_trigger_condition: Return Value here is % for rechnung %', _result, _param_rechnung_id;
				RETURN _result;
			END;
		 $$;


ALTER FUNCTION public.rechnung_trigger_condition(_param_rechnung_id integer) OWNER TO postgres;

--
-- Name: rechnung_trigger_condition_preisoffen_anzahlung(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.rechnung_trigger_condition_preisoffen_anzahlung(_param_rechnung_id integer) RETURNS boolean
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				_result boolean := True;
