				IF _update_preise_dirty THEN
					_result := False;
				ELSE
					SET softwarevision.do_rechnung_update_preisoffen_anzahlung TO 'true';
				END IF;
				UPDATE public.rechnung SET update_anzahlung_preisoffen_dirty = true WHERE id = _param_rechnung_id AND NOT update_anzahlung_preisoffen_dirty;
				-- RAISE NOTICE 'rechnung_trigger_condition: Return Value here is % for rechnung %', _result, _param_rechnung_id;
				RETURN _result;
			END;
		 $$;


ALTER FUNCTION public.rechnung_trigger_condition_preisoffen_anzahlung(_param_rechnung_id integer) OWNER TO postgres;

--
-- Name: rechnung_trigger_condition_preisoffen_anzahlung(integer, integer); Type: FUNCTION; Schema: public; Owner: admin
--

CREATE FUNCTION public.rechnung_trigger_condition_preisoffen_anzahlung(_param_rechnung_id integer, _param_geplante_zahlung_id integer) RETURNS boolean
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				_result boolean := True;
				_update_preise_dirty boolean;
			BEGIN
				IF (public.sv_current_setting('softwarevision.disable_rechnung_update_preise', 'false') = 'true') THEN
					RETURN False;
				END IF;
				SELECT public.sv_current_setting('softwarevision.do_rechnung_update_preisoffen_anzahlung', 'false') INTO _update_preise_dirty;
				IF _update_preise_dirty THEN
					_result := False;
				ELSE
					SET softwarevision.do_rechnung_update_preisoffen_anzahlung TO 'true';
				END IF;
				UPDATE public.rechnung SET update_anzahlung_preisoffen_dirty = true WHERE id = _param_rechnung_id AND NOT update_anzahlung_preisoffen_dirty;
				UPDATE public.rechnung_zahlung_geplant SET update_anzahlung_preisoffen_dirty = true WHERE id = _param_geplante_zahlung_id AND NOT update_anzahlung_preisoffen_dirty;
				-- RAISE NOTICE 'rechnung_trigger_condition: Return Value here is % for rechnung %', _result, _param_rechnung_id;
				RETURN _result;
			END;
		 $$;


ALTER FUNCTION public.rechnung_trigger_condition_preisoffen_anzahlung(_param_rechnung_id integer, _param_geplante_zahlung_id integer) OWNER TO admin;

--
-- Name: rechnung_trigger_preis_update(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.rechnung_trigger_preis_update() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			BEGIN
				-- RAISE NOTICE 'trigger_rechnung_update: Rechnung %', _rechnung_id;
				SET softwarevision.do_rechnung_update_preise TO 'false';
				PERFORM rechnung_update_preise(ARRAY(SELECT id FROM rechnung WHERE update_preise_dirty));
				RETURN NULL;
			END;
		 $$;


ALTER FUNCTION public.rechnung_trigger_preis_update() OWNER TO postgres;

--
-- Name: rechnung_trigger_update_preisoffen_anzahlung(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.rechnung_trigger_update_preisoffen_anzahlung() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			BEGIN
				-- RAISE NOTICE 'trigger_update_preisoffen_anzahlung;
				SET softwarevision.do_rechnung_update_preisoffen_anzahlung TO 'false';
				PERFORM public.geplante_zahlung_update_preisoffen_anzahlung(ARRAY(SELECT id FROM public.rechnung_zahlung_geplant WHERE update_anzahlung_preisoffen_dirty));
				PERFORM public.rechnung_update_preisoffen_anzahlung(ARRAY(SELECT id FROM public.rechnung WHERE update_anzahlung_preisoffen_dirty));
				RETURN NULL;
			END;
		 $$;


ALTER FUNCTION public.rechnung_trigger_update_preisoffen_anzahlung() OWNER TO postgres;

