--
-- Name: rechnung_update_preise(integer[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.rechnung_update_preise(_param_array_rechnung_id integer[]) RETURNS void
    LANGUAGE sql
    AS $$ 
			WITH pos_with_posrabatt AS (
				SELECT pos.*, anzahl * einzelpreis AS _summe,  SUM (
				(CASE WHEN rechnung_rabatt.typ = 1 THEN -- enum RabattTyp { Festbetrag = 1, Prozentual = 2 };
						rechnung_rabatt.betrag
					WHEN rechnung_rabatt.typ = 2 THEN
						(anzahl * einzelpreis * rechnung_rabatt.prozent) / 100
					ELSE 0
					END)
				)  AS _rabatt
				FROM public.rechnung_pos pos
				LEFT JOIN rechnung_rabatt ON rechnung_rabatt.rechpos = pos.id AND rechnung_rabatt.deleted_datum IS NULL
				WHERE pos.deleted_datum IS NULL
				AND pos.rechnung IN (SELECT(UNNEST(_param_array_rechnung_id)))
				GROUP by pos.id
			),
			pos_fix_gutschrift AS (
				SELECT pos.rechnung, typ, SUM(pos._summe) AS _possumme, SUM(pos._rabatt) AS _possummerabatt, SUM(pos._summe - pos._rabatt) AS _possumme_abzgl_rabatt,
				SUM(
					(CASE WHEN r.netto = 0 THEN
						(pos._summe - pos._rabatt)
						* (CASE WHEN mwst_typ = 0 THEN r.mwstsatz0 WHEN mwst_typ = 1 THEN r.mwstsatz1 ELSE 0 END)
						/ (100 + (CASE WHEN mwst_typ = 0 THEN r.mwstsatz0 WHEN mwst_typ = 1 THEN r.mwstsatz1 ELSE 0 END))
					WHEN r.netto = 2 THEN
						(pos._summe - pos._rabatt)
						* (CASE WHEN mwst_typ = 0 THEN r.mwstsatz0 WHEN mwst_typ = 1 THEN r.mwstsatz1 ELSE 0 END) / 100
					ELSE 0
					END)
				) AS _possummemwst
				FROM pos_with_posrabatt pos
				INNER JOIN rechnung r ON r.id = pos.rechnung
				WHERE typ != 7
				GROUP BY pos.rechnung, pos.typ
			UNION ALL
				SELECT pos.rechnung, pos_orig.typ, SUM(pos._summe) AS _possumme, SUM(pos._rabatt) AS _possummerabatt, SUM(pos._summe - pos._rabatt) AS _possumme_abzgl_rabatt,

				SUM(
					(CASE WHEN r.netto = 0 THEN
						(pos._summe - pos._rabatt)
						* (CASE WHEN pos.mwst_typ = 0 THEN r.mwstsatz0 WHEN pos.mwst_typ = 1 THEN r.mwstsatz1 ELSE 0 END)
						/ (100 + (CASE WHEN pos.mwst_typ = 0 THEN r.mwstsatz0 WHEN pos.mwst_typ = 1 THEN r.mwstsatz1 ELSE 0 END))
					WHEN r.netto = 2 THEN
						(pos._summe - pos._rabatt)
						* (CASE WHEN pos.mwst_typ = 0 THEN r.mwstsatz0 WHEN pos.mwst_typ = 1 THEN r.mwstsatz1 ELSE 0 END) / 100
					ELSE 0
					END)
				)
				AS _possummemwst

				FROM public.rechnung_pos_gutschrift _pos
				INNER JOIN pos_with_posrabatt pos USING (id)
				INNER JOIN public.rechnung_pos pos_orig ON pos_orig.id = _pos.pos
				INNER JOIN public.rechnung r ON r.id = pos.rechnung
				WHERE pos.deleted_datum IS NULL
				AND _pos.rechnung IN (SELECT(UNNEST(_param_array_rechnung_id)))
				GROUP BY pos.rechnung, pos_orig.typ
			),
			pos_all_ohne_kk AS (
				SELECT rechnung, SUM( _possumme ) AS _preissumme, SUM(_possummerabatt) AS _preisrabatt, SUM(_possumme_abzgl_rabatt) AS _preissumme_abzgl_rabatt
				FROM pos_fix_gutschrift
				WHERE typ != 3 AND typ != 30	-- RechPosAbrechnung und RechPosAbrechnungPos
				AND rechnung IN (SELECT(UNNEST(_param_array_rechnung_id)))
				GROUP BY rechnung
			),
			pos_kk AS (
				SELECT rechnung, -SUM( _possumme ) AS _preiskk, 0 AS _preisrabatt, 0 AS _preissumme_abzgl_rabatt
				FROM pos_fix_gutschrift
				WHERE typ = 3 OR typ = 30		-- RechPosAbrechnung und RechPosAbrechnungPos
				GROUP BY rechnung
			),
			rabatte AS (
				SELECT rechnung_rabatt.rechnung,
					(   SUM( CASE WHEN rechnung_rabatt.rechpos IS NULL THEN
							  COALESCE(rechnung_rabatt.betrag, 0) +
							  COALESCE(rechnung_rabatt.prozent, 0) * (COALESCE(pos_all_ohne_kk._preissumme_abzgl_rabatt, 0) - COALESCE(pos_kk._preiskk, 0)) / 100
							 ELSE 0 END )
					)::numeric(12,2) AS _rabatt_auftrag,
					MAX(pos_all_ohne_kk._preisrabatt) AS _rabatt_position,
					(   SUM( CASE WHEN rechnung_rabatt.rechpos IS NULL THEN
							  COALESCE(rechnung_rabatt.betrag, 0) +
							  COALESCE(rechnung_rabatt.prozent, 0) * (COALESCE(pos_all_ohne_kk._preissumme_abzgl_rabatt, 0) - COALESCE(pos_kk._preiskk, 0)) / 100
						 ELSE 0 END )
					  + MAX(pos_all_ohne_kk._preisrabatt) -- _preisrabatt ist bereits als Summe berechnet, MAX nur wegen GROUP BY
					)::numeric(12,2) AS _rabatt
				FROM public.rechnung_rabatt rechnung_rabatt
				INNER JOIN pos_all_ohne_kk ON pos_all_ohne_kk.rechnung = rechnung_rabatt.rechnung
				LEFT JOIN pos_kk ON pos_kk.rechnung = rechnung_rabatt.rechnung
				WHERE deleted_datum IS NULL
				AND rechnung_rabatt.rechnung IN (SELECT(UNNEST(_param_array_rechnung_id)))
				GROUP BY rechnung_rabatt.rechnung
			),
			pos_mwst AS (
				SELECT rechnung,
						(CASE WHEN SUM(_possumme_abzgl_rabatt) = 0 THEN 0
							ELSE SUM(_possummemwst) * ( (SUM(_possumme_abzgl_rabatt) - MAX(COALESCE(rabatte._rabatt_auftrag, 0)) ) / SUM(_possumme_abzgl_rabatt) )
							END
						)::numeric(12,2) AS _preismwst
				FROM pos_fix_gutschrift
				LEFT JOIN rabatte using(rechnung)
				GROUP BY pos_fix_gutschrift.rechnung
			), _preis_calculated AS (
			SELECT r.id, COALESCE(pos_all_ohne_kk._preissumme, 0)
					+ CASE WHEN r.netto = 2 THEN COALESCE(pos_mwst._preismwst, 0) ELSE 0 END
					AS preissumme,
				COALESCE(rabatte._rabatt, 0)
					AS rabatt,
				COALESCE(pos_all_ohne_kk._preissumme, 0)
					+ CASE WHEN r.netto = 2 THEN COALESCE(pos_mwst._preismwst, 0) ELSE 0 END
					- COALESCE(rabatte._rabatt, 0)
					AS preisumsatz,
				COALESCE(pos_all_ohne_kk._preissumme, 0)
					+ CASE WHEN r.netto = 2 THEN COALESCE(pos_mwst._preismwst, 0) ELSE 0 END
					- COALESCE(rabatte._rabatt, 0)
					- COALESCE(r.skonto, 0)
					AS preisumsatz_skonto,
				COALESCE(pos_kk._preiskk, 0)
					AS preiskk,
				COALESCE(pos_all_ohne_kk._preissumme, 0)
					+ CASE WHEN r.netto = 2 THEN COALESCE(pos_mwst._preismwst, 0) ELSE 0 END
					- COALESCE(rabatte._rabatt, 0)
					- COALESCE(pos_kk._preiskk, 0)
					AS preisrechnung,
				COALESCE(pos_all_ohne_kk._preissumme, 0)
					+ CASE WHEN r.netto = 2 THEN COALESCE(pos_mwst._preismwst, 0) ELSE 0 END
					- COALESCE(rabatte._rabatt, 0)
					- COALESCE(pos_kk._preiskk, 0)
					- COALESCE(r.skonto, 0)
					AS preisrechnung_skonto
			FROM public.rechnung r
			LEFT JOIN pos_all_ohne_kk ON pos_all_ohne_kk.rechnung = r.id
			LEFT JOIN pos_kk ON pos_kk.rechnung = r.id
			LEFT JOIN rabatte ON rabatte.rechnung = r.id
			LEFT JOIN pos_mwst ON pos_mwst.rechnung = r.id
			WHERE r.id IN (SELECT(UNNEST(_param_array_rechnung_id)))
			)
			UPDATE public.rechnung r SET update_preise_dirty = false, preissumme = pc.preissumme, rabatt = pc.rabatt, preisumsatz = pc.preisumsatz, preisumsatz_skonto = pc.preisumsatz_skonto, preiskk = pc.preiskk, preisrechnung = pc.preisrechnung, preisrechnung_skonto = pc.preisrechnung_skonto
			FROM _preis_calculated pc WHERE pc.id = r.id;
		 $$;


ALTER FUNCTION public.rechnung_update_preise(_param_array_rechnung_id integer[]) OWNER TO postgres;

--
-- Name: rechnung_update_preise2(integer[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.rechnung_update_preise2(VARIADIC _param_array_rechnung_id integer[]) RETURNS void
    LANGUAGE sql
    AS $$ 
			SELECT public.rechnung_update_preise(_param_array_rechnung_id);
		 $$;


ALTER FUNCTION public.rechnung_update_preise2(VARIADIC _param_array_rechnung_id integer[]) OWNER TO postgres;

--
-- Name: rechnung_update_preisoffen_anzahlung(integer[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.rechnung_update_preisoffen_anzahlung(_param_array_rechnung_id integer[]) RETURNS void
    LANGUAGE sql
    AS $$ 
			WITH _zahlungen AS (
				SELECT rechnung, SUM( betrag ) AS _anzahlung
				FROM public.rechnung_zahlung_geleistet
				WHERE deleted_datum IS NULL
				AND rechnung IN (SELECT(UNNEST(_param_array_rechnung_id)))
				GROUP BY rechnung
			),
			_zahlungen_geplant AS (
				SELECT rechnung, SUM( betrag ) AS _geplant
				FROM public.rechnung_zahlung_geplant
				WHERE deleted_datum IS NULL
				AND rechnung IN (SELECT(UNNEST(_param_array_rechnung_id)))
				GROUP BY rechnung
			),
			_preis_calculated AS (
				SELECT r.id,
					CASE WHEN zahlmodus = 3 -- Abo
					THEN preisrechnung_skonto
					WHEN zahlmodus IN (1, 2, 5, 6)  -- Einmalzahlung, Ratenzahlung, Gutschrift und KVA
					THEN COALESCE(_zahlungen_geplant._geplant, 0)
					  - COALESCE(_zahlungen._anzahlung, 0)
					ELSE preisrechnung_skonto
				END AS _offen,
				COALESCE(_zahlungen._anzahlung, 0) AS _anzahlung
				FROM public.rechnung r
				LEFT JOIN _zahlungen_geplant ON r.id = _zahlungen_geplant.rechnung
				LEFT JOIN _zahlungen ON r.id = _zahlungen.rechnung
				WHERE r.id IN (SELECT(UNNEST(_param_array_rechnung_id)))
			)
			UPDATE public.rechnung r SET update_anzahlung_preisoffen_dirty = false, preisoffen = pc._offen, anzahlung = pc._anzahlung
			FROM _preis_calculated pc WHERE pc.id = r.id;
		 $$;


ALTER FUNCTION public.rechnung_update_preisoffen_anzahlung(_param_array_rechnung_id integer[]) OWNER TO postgres;

--
-- Name: rechnung_zahlmodus_changed(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rechnung_zahlmodus_changed() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			BEGIN
				IF (TG_OP = 'INSERT') THEN
					NEW.zahlmodus_datum = NOW();
				ELSIF (NEW.zahlmodus != OLD.zahlmodus) THEN
					NEW.zahlmodus_datum = NOW();
				END IF;
				RETURN NEW;
			END
		 $$;


ALTER FUNCTION public.rechnung_zahlmodus_changed() OWNER TO adc;

--
-- Name: rechpos_linse_update_price(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rechpos_linse_update_price() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			BEGIN
				CASE NEW.art
				WHEN 1 THEN --Einzel
					NEW.re_system = NULL;
					NEW.li_system = NULL;
					NEW.pflege = NULL;
					NEW.system_preis = NULL;
					NEW.pflege_preis = NULL;
					NEW.re_preisverlust = NULL;
					NEW.li_preisverlust = NULL;
					NEW.einzelpreis = COALESCE(NEW.re_preis, 0) + COALESCE(NEW.li_preis, 0);
				WHEN 2 THEN --System
					NEW.re_anzahl = NULL;
					NEW.li_anzahl = NULL;
					NEW.re_boxinhalt = NULL;
					NEW.li_boxinhalt = NULL;
					NEW.re_preis = NULL;
					NEW.li_preis = NULL;
					NEW.einzelpreis = COALESCE(NEW.system_preis, 0) + COALESCE(NEW.pflege_preis, 0);
				WHEN 3 THEN --Boxen
					NEW.re_system = NULL;
					NEW.li_system = NULL;
					NEW.pflege = NULL;
					NEW.system_preis = NULL;
					NEW.pflege_preis = NULL;
					NEW.re_preisverlust = NULL;
					NEW.li_preisverlust = NULL;
					NEW.einzelpreis = COALESCE(NEW.re_anzahl*NEW.re_preis, 0) + COALESCE(NEW.li_anzahl*NEW.li_preis, 0);
				ELSE
					RAISE 'Ungültiger Linsen-Typ %.', NEW.art USING HINT = 'Gültige Werte sind 1 (Einzel), 2 (System), 3 (Boxen)';
				END CASE;

				RETURN NEW;
			END;
		 $$;


ALTER FUNCTION public.rechpos_linse_update_price() OWNER TO adc;

--
-- Name: rm_delete_functionright(text, integer, integer, text, text); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_delete_functionright(OUT ok_ boolean, OUT result_ integer, function_name_ text, role_id_ integer, operator_id_ integer, operator_pw_ text, hostname_ text) RETURNS record
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			DECLARE
				deleted_ids INTEGER;
			BEGIN
				ok_ := false;

				DELETE FROM public.rm_restrictable_functions
				WHERE 	function_name = function_name_
					AND role_id = role_id_
				RETURNING id INTO deleted_ids;

				IF NOT FOUND THEN
					result_ := 2;
					RETURN;
				END IF;

				UPDATE public.rm_restrictable_functions_log
				SET		modified_by_proguser = operator_id_
					, modified_at_hostname = hostname_
				WHERE 	function_name = function_name_
					AND role_id = role_id_
					AND mod_type = 'DELETE'
					AND id IN ( deleted_ids );

				IF NOT FOUND THEN
					result_ := 3;
					RETURN;
				END IF;

				ok_ := true;
				result_ := 0;
			END;
		 $$;


ALTER FUNCTION public.rm_delete_functionright(OUT ok_ boolean, OUT result_ integer, function_name_ text, role_id_ integer, operator_id_ integer, operator_pw_ text, hostname_ text) OWNER TO adc;

--
-- Name: rm_delete_userrole(integer, integer, text, text); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_delete_userrole(OUT ok_ boolean, OUT result_ integer, role_id_ integer, operator_id_ integer, operator_pw_ text, hostname_ text) RETURNS record
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			DECLARE
				del_childrole_id				INTEGER;
				del_role_possession_interval	public.rm_userrole_members;
				del_restrictable_function_name	TEXT;
				del_funcrole_interval_id		INTEGER := -1;
				loop_ok							BOOLEAN := false;
				loop_result						INTEGER := 0;
			BEGIN
				ok_ := false;

				FOR del_childrole_id IN
					SELECT delroles.id
					FROM public.rm_userroles as delroles
					WHERE delroles.parent_id = role_id_
				LOOP
					SELECT INTO loop_ok, loop_result
							deleteChild.ok_, deleteChild.result_
							FROM public.rm_delete_userrole( del_childrole_id, operator_id_, operator_pw_, hostname_ ) AS deleteChild;
					IF NOT loop_ok THEN
						result_ := 10 * loop_result + 2;
						RETURN;
					END IF;
				END LOOP;

				FOR del_role_possession_interval IN
					SELECT role_members.*
					FROM public.rm_userrole_members as role_members
					WHERE 	role_members.role_id = role_id_
						AND COALESCE( role_members.valid_to, LOCALTIMESTAMP ) >= LOCALTIMESTAMP
				LOOP
					SELECT INTO loop_ok, loop_result
						saveRole.ok_, saveRole.result_
						FROM public.rm_save_userrole_interval(	 del_role_possession_interval.id
																, del_role_possession_interval.user_id
																, role_id_
																, del_role_possession_interval.valid_from::TIMESTAMP with time zone
																, LOCALTIMESTAMP::TIMESTAMP with time zone
																, operator_id_
																, operator_pw_
																, hostname_ ) AS saveRole;
					IF NOT loop_ok THEN
						result_ := 10 * loop_result + 3;
						RETURN;
					END IF;
				END LOOP;

				FOR del_restrictable_function_name IN
					SELECT fns.function_name
					FROM public.rm_restrictable_functions as fns
					WHERE fns.role_id = role_id_
				LOOP
					SELECT INTO loop_ok, loop_result
								deleteRight.ok_, deleteRight.result_
								FROM public.rm_delete_functionright( del_restrictable_function_name, role_id_, operator_id_, operator_pw_, hostname_ ) AS deleteRight;
					IF NOT loop_ok THEN
						result_ := 10 * loop_result + 4;
						RETURN;
					END IF;
				END LOOP;

				UPDATE public.rm_userroles
				SET active = FALSE
				WHERE 	id = role_id_
					AND active = TRUE;

				IF NOT FOUND THEN
					ok_ := true;
					result_ := 2;
					RETURN;
				END IF;

				UPDATE public.rm_userroles_log
				SET		modified_by_proguser = operator_id_
					, modified_at_hostname = hostname_
				WHERE mod_id = (
					SELECT MAX(mod_id) AS maxModID
					FROM rm_userroles_log as innertable
					WHERE innertable.id = role_id_ );

				IF NOT FOUND THEN
					result_ := 6;
					RETURN;
				END IF;

				ok_ := true;
				result_ := 0;
			END;
		 $$;


ALTER FUNCTION public.rm_delete_userrole(OUT ok_ boolean, OUT result_ integer, role_id_ integer, operator_id_ integer, operator_pw_ text, hostname_ text) OWNER TO adc;

--
-- Name: rm_delete_userrole_interval(integer, integer, text, text); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_delete_userrole_interval(OUT ok_ boolean, OUT result_ integer, interval_id_ integer, operator_id_ integer, operator_pw_ text, hostname_ text) RETURNS record
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			BEGIN
				ok_ := false;

				DELETE FROM public.rm_userrole_members
				WHERE 	id = interval_id_;

				IF NOT FOUND THEN
					result_ := 2;
					RETURN;
				END IF;

				UPDATE public.rm_userrole_members_log
				SET		modified_by_proguser = operator_id_
					, modified_at_hostname = hostname_
				WHERE 	id = interval_id_
					AND mod_type = 'DELETE';

				IF NOT FOUND THEN
					result_ := 3;
					RETURN;
				END IF;

				ok_ := true;
				result_ := 0;
			END;
		 $$;


ALTER FUNCTION public.rm_delete_userrole_interval(OUT ok_ boolean, OUT result_ integer, interval_id_ integer, operator_id_ integer, operator_pw_ text, hostname_ text) OWNER TO adc;

--
-- Name: rm_get_pw_status(integer); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_get_pw_status(user_id_ integer, OUT pw_status_ integer, OUT pw_single_use_ boolean) RETURNS record
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			DECLARE
				this_expires_ts	TIMESTAMP;
				this_warn_ts	TIMESTAMP;
				now_ts			TIMESTAMP := LOCALTIMESTAMP;
			BEGIN
				pw_single_use_ := false;
				IF ( SELECT pw.user_id FROM public.rm_user_pw AS pw WHERE pw.user_id = user_id_ ) IS NULL THEN
					pw_status_ := 1;
					RETURN;
				ELSEIF (	SELECT pw.user_id
							FROM public.rm_user_pw AS pw
							WHERE pw.user_id = user_id_
								AND pw.pw_hash IS NULL
								AND pw.md5_hash IS NULL ) IS NOT NULL THEN
					pw_status_ := 2;
					RETURN;
				END IF;
				SELECT INTO pw_single_use_, this_expires_ts, this_warn_ts
							pw.single_use, COALESCE( pw.expires_ts, now_ts ), COALESCE( pw.warn_ts, now_ts )
							FROM public.rm_user_pw AS pw
							WHERE pw.user_id = user_id_;
				IF ( now_ts > this_expires_ts )	THEN
					pw_status_ := 3;
				ELSEIF ( now_ts > this_warn_ts ) THEN
					pw_status_ := 5;
				ELSE
					pw_status_ := 4;
				END IF;
			END;
		 $$;


ALTER FUNCTION public.rm_get_pw_status(user_id_ integer, OUT pw_status_ integer, OUT pw_single_use_ boolean) OWNER TO adc;

--
-- Name: rm_log_restrictable_functions(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_log_restrictable_functions() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			BEGIN
				-- Create a row in public.rm_restrictable_functions_log to reflect the operation performed on public.rm_restrictable_functions
				IF (TG_OP = 'DELETE') THEN
					INSERT INTO public.rm_restrictable_functions_log ( id, function_name, role_id, permitted, mod_type )
															VALUES ( OLD.id, OLD.function_name, OLD.role_id, OLD.permitted, TG_OP );
				ELSE
					INSERT INTO public.rm_restrictable_functions_log ( id, function_name, role_id, permitted, 
																	modified_at_hostname, modified_by_proguser, mod_type )
															VALUES ( NEW.id, NEW.function_name, NEW.role_id, NEW.permitted, 
																	NEW.modified_at_hostname, NEW.modified_by_proguser, TG_OP );
				END IF;
				RETURN NULL; -- result is ignored since this is an AFTER trigger
			END;
		 $$;


ALTER FUNCTION public.rm_log_restrictable_functions() OWNER TO adc;

--
-- Name: rm_log_user_pw(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_log_user_pw() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			BEGIN
				-- Create a row in public.rm_user_pw_log to reflect the operation performed on public.rm_user_pw
				IF (TG_OP = 'DELETE') THEN
					INSERT INTO public.rm_user_pw_log ( user_id, pw_hash, md5_hash, md5_salt,
														last_invalid_login, invalid_login_count,
														single_use, expires_ts, warn_ts, mod_type )
												VALUES( OLD.user_id, OLD.pw_hash, OLD.md5_hash,
														OLD.md5_salt, OLD.last_invalid_login, OLD.invalid_login_count,
														OLD.single_use, OLD.expires_ts, OLD.warn_ts, TG_OP );
				ELSE
					INSERT INTO public.rm_user_pw_log ( user_id, pw_hash, md5_hash, md5_salt,
														last_invalid_login, invalid_login_count,
														single_use, expires_ts, warn_ts,
														modified_at_hostname, modified_by_proguser, mod_type )
												VALUES( NEW.user_id, NEW.pw_hash, NEW.md5_hash, NEW.md5_salt,
														NEW.last_invalid_login, NEW.invalid_login_count,
														NEW.single_use, NEW.expires_ts, NEW.warn_ts,
														NEW.modified_at_hostname, NEW.modified_by_proguser, TG_OP );
				END IF;
				RETURN NULL; -- result is ignored since this is an AFTER trigger
			END;
		 $$;


ALTER FUNCTION public.rm_log_user_pw() OWNER TO adc;

