--
-- Name: rm_login_ok(integer, text, text); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_login_ok(user_id_ integer, pw_ text, hostname_ text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			BEGIN
				IF public.rm_pw_ok( user_id_, pw_ ) THEN
					UPDATE public.rm_user_pw
					SET invalid_login_count = 0,
						modified_by_proguser = NULL,	-- since this is set at login, no user is logged in yet and the attempt was probably made by this user_id
						modified_at_hostname = hostname_
					WHERE 	user_id = user_id_
						AND invalid_login_count != 0;	-- only reset invalid login counter if it is set
					RETURN TRUE;
				ELSE
					UPDATE public.rm_user_pw
					SET	invalid_login_count = ( invalid_login_count + 1 ),
						last_invalid_login = LOCALTIMESTAMP,
						modified_by_proguser = NULL,	-- since this is set at login, no user is logged in yet and the attempt was probably made by this user_id
						modified_at_hostname = hostname_
					WHERE public.rm_user_pw.user_id = user_id_;
					RETURN FALSE;
				END IF;
			END;
		 $$;


ALTER FUNCTION public.rm_login_ok(user_id_ integer, pw_ text, hostname_ text) OWNER TO adc;

--
-- Name: rm_pw_correct(integer, text); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_pw_correct(user_id_ integer, pw_ text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			DECLARE
			-- We do this first part no matter what, just to foil attacks that monitor execution time.
			-- NULL parameters end up using the defaultSalt, performing an UPDATE on an empty set and returning false

			--	ATTENTION: when switching over from md5 to pgcrypto remember to UPDATE rm_user_pw with pgcrypto password hashes and NULLing the md5 hashes
			-- 	default_salt	TEXT := pgcrypto.gen_salt( 'bf' );
			-- 	stored_hash		TEXT := COALESCE( ( SELECT pw.pw_hash FROM public.rm_user_pw AS pw WHERE pw.user_id = user_id_ ), default_salt );
			-- 	test_hash		TEXT := pgcrypto.crypt( pw_, stored_hash );

				stored_salt	TEXT := COALESCE( ( SELECT pw.md5_salt FROM public.rm_user_pw AS pw WHERE pw.user_id = user_id_ ), 'Dies ist ein kaputtes Salt' );
				stored_hash	TEXT := COALESCE( ( SELECT pw.md5_hash FROM public.rm_user_pw AS pw WHERE pw.user_id = user_id_ ), 'Dies ist ein kaputter Hash' );
				test_hash	TEXT := md5( stored_salt || COALESCE( pw_, stored_hash ) );	-- NULL PWs should always fail: we compare the stored PW hash with, in turn, its hash
			BEGIN
				RETURN( test_hash = stored_hash );
			END;
		 $$;


ALTER FUNCTION public.rm_pw_correct(user_id_ integer, pw_ text) OWNER TO adc;

--
-- Name: rm_pw_found(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_pw_found() RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			BEGIN
				RETURN ( SELECT COUNT(pw_hash) + COUNT(md5_hash) FROM public.rm_user_pw ) > 0;
			END;
		 $$;


ALTER FUNCTION public.rm_pw_found() OWNER TO adc;

--
-- Name: rm_pw_found_for_user(integer); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_pw_found_for_user(user_id_ integer) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			BEGIN
				RETURN ( SELECT COUNT(pw.pw_hash) + COUNT(pw.md5_hash) FROM public.rm_user_pw AS pw WHERE pw.user_id = user_id_ ) > 0;
			END;
		 $$;


ALTER FUNCTION public.rm_pw_found_for_user(user_id_ integer) OWNER TO adc;

--
-- Name: rm_pw_ok(integer, text); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_pw_ok(user_id_ integer, pw_ text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			DECLARE
				pw_correct	BOOLEAN := rm_pw_correct( user_id_, pw_ );
				pw_status	INTEGER	:= pw_status_ FROM public.rm_get_pw_status( user_id_ );
			BEGIN
				RETURN( pw_correct AND pw_status IN ( 4, 5 ) );
			END;
		 $$;


ALTER FUNCTION public.rm_pw_ok(user_id_ integer, pw_ text) OWNER TO adc;

--
-- Name: rm_save_functionright(text, integer, boolean, integer, text, text); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_save_functionright(OUT ok_ boolean, OUT result_ integer, function_name_ text, role_id_ integer, permitted_ boolean, operator_id_ integer, operator_pw_ text, hostname_ text) RETURNS record
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			BEGIN
				ok_ := false;

				IF ( SELECT id FROM public.rm_userroles WHERE id = role_id_ AND active IS TRUE ) IS NULL THEN
					result_ := 2;
					RETURN;
				END IF;

				UPDATE public.rm_restrictable_functions
				SET	 permitted = permitted_
					, modified_by_proguser = operator_id_
					, modified_at_hostname = hostname_
				WHERE 	function_name = function_name_
					AND role_id = role_id_;

				ok_ := true;

				IF NOT FOUND THEN
					INSERT INTO public.rm_restrictable_functions( function_name, role_id, permitted, modified_by_proguser, modified_at_hostname )
															VALUES( function_name_, role_id_, permitted_, operator_id_, hostname_ );
					result_ := 3;
					RETURN;
				END IF;

				result_ := 4;
			END;
		 $$;


ALTER FUNCTION public.rm_save_functionright(OUT ok_ boolean, OUT result_ integer, function_name_ text, role_id_ integer, permitted_ boolean, operator_id_ integer, operator_pw_ text, hostname_ text) OWNER TO adc;

--
-- Name: rm_save_userrole(integer, integer, text, text, integer, text, text); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_save_userrole(OUT ok_ boolean, OUT result_ integer, role_id_ integer, parent_id_ integer, role_name_ text, description_ text, operator_id_ integer, operator_pw_ text, hostname_ text) RETURNS record
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			BEGIN
				ok_ := false;

				IF role_id_ < 0 THEN
					result_ := 2;
					RETURN;
				END IF;

				IF role_id_ = 0 AND parent_id_ != -1 THEN
					result_ := 3;
					RETURN;
				END IF;

				IF ( role_id_ != 0	AND ( SELECT id FROM public.rm_userroles WHERE id = parent_id_ ) IS NULL ) THEN
					result_ := 4;
					RETURN;
				END IF;

				IF ( SELECT id FROM public.rm_userroles WHERE role_name = role_name_ AND active = TRUE ) != role_id_ THEN
					result_ := 5;
					RETURN;
				END IF;

				UPDATE public.rm_userroles
				SET	 role_name = role_name_
					, description = description_
					, modified_by_proguser = operator_id_
					, modified_at_hostname = hostname_
				WHERE id = role_id_;

				ok_ := true;
				IF NOT FOUND THEN
					INSERT INTO public.rm_userroles( id, parent_id, role_name, description, modified_by_proguser, modified_at_hostname )
							VALUES( role_id_, parent_id_, role_name_, description_, operator_id_, hostname_ );
					result_ := 6;
					RETURN;
				END IF;

				result_ := 7;
			END;
		 $$;


ALTER FUNCTION public.rm_save_userrole(OUT ok_ boolean, OUT result_ integer, role_id_ integer, parent_id_ integer, role_name_ text, description_ text, operator_id_ integer, operator_pw_ text, hostname_ text) OWNER TO adc;

--
-- Name: rm_save_userrole_interval(integer, integer, integer, timestamp without time zone, timestamp without time zone, integer, text, text); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_save_userrole_interval(OUT ok_ boolean, OUT result_ integer, INOUT interval_id_ integer, user_id_ integer, role_id_ integer, valid_from_ timestamp without time zone, valid_to_ timestamp without time zone, operator_id_ integer, operator_pw_ text, hostname_ text) RETURNS record
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			DECLARE
				valid_from_corrected 	TIMESTAMP := COALESCE( valid_from_, LOCALTIMESTAMP );
				valid_to_corrected		TIMESTAMP := CASE WHEN valid_to_ IS NULL THEN valid_to_ ELSE GREATEST( valid_from_corrected, valid_to_ ) END;	-- valid_to = NULL: eternal interval
			BEGIN
				ok_ := false;
				IF NOT public.rm_pw_ok( operator_id_, operator_pw_ ) THEN		-- check PW
					result_ := 1;
				ELSEIF ( SELECT id FROM public.personen WHERE id = user_id_ ) IS NULL THEN		-- check FK user_id
					result_ := 2;
				ELSEIF ( SELECT id FROM public.rm_userroles WHERE id = role_id_ ) IS NULL THEN	-- check FK role_id
					result_ := 3;
				ELSEIF interval_id_ > 0 THEN	-- interval should exist already: UPDATE
					-- make sure this interval isn't over yet
					IF ( SELECT valid_to FROM public.rm_userrole_members WHERE id = interval_id_ ) < LOCALTIMESTAMP THEN
						result_ := 4;
						RETURN;
					END IF;

					-- auto-correct interval end
					UPDATE public.rm_userrole_members
					SET   valid_from = CASE WHEN valid_from <= LOCALTIMESTAMP THEN valid_from ELSE valid_from_corrected END
						, valid_to = valid_to_corrected
						, modified_by_proguser = operator_id_
						, modified_at_hostname = hostname_
					WHERE id = interval_id_;

					IF NOT FOUND THEN
						result_ := 5;		-- interval with ID interval_id_ did not exist
					ELSEIF ( SELECT id FROM public.rm_userrole_members WHERE id = interval_id_ AND ( valid_to IS NULL OR valid_from < valid_to ) ) IS NULL THEN
						-- interval is empty (valid_from >= valid_to )  -->  delete
						SELECT INTO ok_, result_
								delInterval.ok_, delInterval.result_
								FROM public.rm_delete_userrole_interval( interval_id_, operator_id_, operator_pw_, hostname_ ) AS delInterval;
						result_ := result_ * 10 + 7;	-- 7 = success, 37 = failure to UPDATE log table
					ELSE				-- everything went fine
						ok_ := true;
						result_ := 6;
					END IF;
				ELSE -- interval_id_ <= 0 ? -> insert new interval
					IF valid_from_corrected = valid_to_corrected THEN
						result_ := 7;
						RETURN;
					END IF;

					IF ( SELECT id FROM public.rm_userroles WHERE id = role_id_ AND active IS TRUE ) IS NULL THEN	-- check that role is active
						result_ := 3;
						RETURN;
					END IF;

					INSERT INTO public.rm_userrole_members( user_id, role_id, valid_from, valid_to, modified_by_proguser, modified_at_hostname )
					VALUES( user_id_
							, role_id_
							, valid_from_corrected
							, valid_to_corrected
							, operator_id_
							, hostname_ )
					RETURNING id INTO interval_id_;

					IF NOT FOUND THEN
						result_ := 8;
					ELSE
						ok_ := true;
						result_ := 9;
					END IF;
				END IF;
			END;
		 $$;


ALTER FUNCTION public.rm_save_userrole_interval(OUT ok_ boolean, OUT result_ integer, INOUT interval_id_ integer, user_id_ integer, role_id_ integer, valid_from_ timestamp without time zone, valid_to_ timestamp without time zone, operator_id_ integer, operator_pw_ text, hostname_ text) OWNER TO adc;

--
-- Name: rm_save_userrole_interval(integer, integer, integer, timestamp with time zone, timestamp with time zone, integer, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.rm_save_userrole_interval(OUT ok_ boolean, OUT result_ integer, INOUT interval_id_ integer, user_id_ integer, role_id_ integer, valid_from_ timestamp with time zone, valid_to_ timestamp with time zone, operator_id_ integer, operator_pw_ text, hostname_ text) RETURNS record
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			DECLARE
				valid_from_corrected 	TIMESTAMP with time zone := COALESCE( valid_from_, LOCALTIMESTAMP );
				valid_to_corrected		TIMESTAMP with time zone := CASE WHEN valid_to_ IS NULL THEN valid_to_ ELSE GREATEST( valid_from_corrected, valid_to_ ) END;	-- valid_to = NULL: eternal interval
			BEGIN
				ok_ := false;
				IF NOT public.rm_pw_ok( operator_id_, operator_pw_ ) THEN		-- check PW
					result_ := 1;
				ELSEIF ( SELECT id FROM public.personen WHERE id = user_id_ ) IS NULL THEN		-- check FK user_id
					result_ := 2;
				ELSEIF ( SELECT id FROM public.rm_userroles WHERE id = role_id_ ) IS NULL THEN	-- check FK role_id
					result_ := 3;
				ELSEIF interval_id_ > 0 THEN	-- interval should exist already: UPDATE
					-- make sure this interval isn't over yet
					IF ( SELECT valid_to FROM public.rm_userrole_members WHERE id = interval_id_ ) < LOCALTIMESTAMP THEN
						result_ := 4;
						RETURN;
					END IF;

					-- auto-correct interval end
					UPDATE public.rm_userrole_members
					SET   valid_from = CASE WHEN valid_from <= LOCALTIMESTAMP THEN valid_from ELSE valid_from_corrected END
						, valid_to = valid_to_corrected
						, modified_by_proguser = operator_id_
						, modified_at_hostname = hostname_
					WHERE id = interval_id_;

					IF NOT FOUND THEN
						result_ := 5;		-- interval with ID interval_id_ did not exist
					ELSEIF ( SELECT id FROM public.rm_userrole_members WHERE id = interval_id_ AND ( valid_to IS NULL OR valid_from < valid_to ) ) IS NULL THEN
						-- interval is empty (valid_from >= valid_to )  -->  delete
						SELECT INTO ok_, result_
								delInterval.ok_, delInterval.result_
								FROM public.rm_delete_userrole_interval( interval_id_, operator_id_, operator_pw_, hostname_ ) AS delInterval;
						result_ := result_ * 10 + 7;	-- 7 = success, 37 = failure to UPDATE log table
					ELSE				-- everything went fine
						ok_ := true;
						result_ := 6;
					END IF;
				ELSE -- interval_id_ <= 0 ? -> insert new interval
					IF valid_from_corrected = valid_to_corrected THEN
						result_ := 7;
						RETURN;
					END IF;

					IF ( SELECT id FROM public.rm_userroles WHERE id = role_id_ AND active IS TRUE ) IS NULL THEN	-- check that role is active
						result_ := 3;
						RETURN;
					END IF;

					INSERT INTO public.rm_userrole_members( user_id, role_id, valid_from, valid_to, modified_by_proguser, modified_at_hostname )
					VALUES( user_id_
							, role_id_
							, valid_from_corrected
							, valid_to_corrected
							, operator_id_
							, hostname_ )
					RETURNING id INTO interval_id_;

					IF NOT FOUND THEN
						result_ := 8;
					ELSE
						ok_ := true;
						result_ := 9;
					END IF;
				END IF;
			END;
		 $$;


ALTER FUNCTION public.rm_save_userrole_interval(OUT ok_ boolean, OUT result_ integer, INOUT interval_id_ integer, user_id_ integer, role_id_ integer, valid_from_ timestamp with time zone, valid_to_ timestamp with time zone, operator_id_ integer, operator_pw_ text, hostname_ text) OWNER TO postgres;

--
-- Name: rm_set_password(integer, text, integer, text, boolean, integer, timestamp without time zone, timestamp without time zone, text); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.rm_set_password(user_id_ integer, new_pw_ text, operator_id_ integer, operator_pw_ text, pw_single_use_ boolean, exp_update_mode integer, new_expires_ts_ timestamp without time zone, new_warn_ts_ timestamp without time zone, modified_at_hostname_ text) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			DECLARE
				-- we do this first part no matter what, just to foil attacks that monitor execution time
				-- 	new_hash			TEXT := pgcrypto.crypt( newpw, pgcrypto.gen_salt( 'bf' ) );
				-- 	new_md5_salt		TEXT := NULL;
				-- 	new_md5_hash		TEXT := NULL;
				new_hash			TEXT := NULL;
				new_md5_salt		TEXT := COALESCE( user_id_, -1 ) || ' <- ' || COALESCE( operator_id_, -1 );
				new_md5_hash		TEXT := md5( new_md5_salt || COALESCE( new_pw_, '' ) );

				operator_id_valid	BOOLEAN := ( SELECT COUNT( pers.id ) FROM public.personen AS pers WHERE operator_id_ >= 0 AND pers.id = operator_id_ ) = 1;
				operator_pw_correct	BOOLEAN := public.rm_pw_correct( operator_id_, operator_pw_ );	-- we only test if the PW is correct, not if it has expired
				first_user_sets_pw	BOOLEAN := NOT public.rm_pw_found() AND operator_id_ = user_id_; -- the first user on a new system can set his own initial PW

				default_expire_interval	INTERVAL := INTERVAL '30 days';	-- TODO: read from rm_config
				default_warn_interval	INTERVAL := INTERVAL '23 days';	-- TODO: read from rm_config
				default_expires_ts		TIMESTAMP := LOCALTIMESTAMP + default_expire_interval;
				default_warn_ts			TIMESTAMP := LOCALTIMESTAMP + default_warn_interval;

				new_expires_ts		TIMESTAMP := CASE WHEN exp_update_mode = 1 THEN new_expires_ts_ ELSE default_expires_ts END;
				new_warn_ts 		TIMESTAMP := CASE WHEN exp_update_mode = 1 THEN new_warn_ts_ ELSE default_warn_ts END;
			BEGIN
				IF new_pw_ IS NULL THEN
					new_hash 	= NULL;
					new_md5_hash 	= NULL;
					new_md5_salt	= NULL;
				END IF;

				-- check parameters for validity:
				-- this operation can only be performed for a valid user
				IF ( SELECT COUNT( pers.id ) FROM public.personen AS pers WHERE user_id_ >= 0 AND pers.id = user_id_ ) != 1 THEN
					RETURN 1;
				END IF;

				-- this operation can only be performed by a valid operator
				IF NOT operator_id_valid THEN
					RETURN 2;
				END IF;

				-- we need either a valid operator PW or we have to be the first user on a freshly installed system
				IF NOT operator_pw_correct AND NOT first_user_sets_pw THEN
					RETURN 3;
				END IF;

				UPDATE public.rm_user_pw
				SET	  pw_hash = new_hash
					, md5_hash = new_md5_hash
					, md5_salt = new_md5_salt
					, single_use = pw_single_use_
					, expires_ts = CASE WHEN exp_update_mode = 2 THEN expires_ts ELSE new_expires_ts END
					, warn_ts = CASE WHEN exp_update_mode = 2 THEN warn_ts ELSE new_warn_ts END
					, modified_by_proguser = operator_id_
					, modified_at_hostname = modified_at_hostname_
				WHERE user_id = user_id_;

				IF( NOT FOUND ) THEN
					INSERT INTO public.rm_user_pw( user_id, pw_hash, md5_hash, md5_salt, single_use,
													expires_ts,
													warn_ts,
													modified_by_proguser, modified_at_hostname )
											VALUES ( user_id_, new_hash, new_md5_hash, new_md5_salt, pw_single_use_,
													CASE WHEN exp_update_mode = 2 THEN NULL ELSE new_expires_ts END,
													CASE WHEN exp_update_mode = 2 THEN NULL ELSE new_warn_ts END,
													operator_id_, modified_at_hostname_ );
				END IF;
				RETURN 0;	-- success!
			END;
		 $$;


ALTER FUNCTION public.rm_set_password(user_id_ integer, new_pw_ text, operator_id_ integer, operator_pw_ text, pw_single_use_ boolean, exp_update_mode integer, new_expires_ts_ timestamp without time zone, new_warn_ts_ timestamp without time zone, modified_at_hostname_ text) OWNER TO adc;

--
-- Name: strasse_mit_hausnummer(text, text); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.strasse_mit_hausnummer(strasse_ text, hausnummer_ text) RETURNS text
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				result_ text;

			BEGIN
				result_ := TRIM(strasse_) || ' ';
				IF LENGTH(hausnummer_) > 0 THEN
					result_ := result_ || hausnummer_ || ' ';
				END IF;
				RETURN TRIM(result_);
			END;
		 $$;


