--

CREATE FUNCTION public.sv_current_setting(parameter_ text) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$ 
			DECLARE
				sResult text;
			BEGIN
				BEGIN
					sResult = current_setting(parameter_);
					EXCEPTION WHEN undefined_object THEN
						sResult = NULL
					RETURN;
				END;

				RETURN NULLIF(sResult, '');
			END;
		 $$;


