--
-- Name: sv_lock_acquire(text, text, text); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.sv_lock_acquire(wert_in text, name_in text, infotext_in text, OUT acquired boolean, OUT name text, OUT infotext text) RETURNS record
    LANGUAGE plpgsql
    AS $$
							   declare
								   r record;
							   begin
								   -- Double-checked locking: check 1
								   for r in select sv_lock_is_timestamp_alive(l.datum) as alive,
										   l.name, l.infotext from public.locks l
										   where l.wert = wert_in loop
									   if r.alive then
										   acquired = FALSE;
										   name = r.name;
										   infotext = r.infotext;
										   return;
									   end if;
								   end loop;
								   lock table public.locks in exclusive mode;
								   -- Double-checked locking: check 2
								   for r in select sv_lock_is_timestamp_alive(l.datum) as alive,
										   l.name, l.infotext from public.locks l
										   where l.wert = wert_in loop
									   if r.alive then
										   -- Exists, but already taken
										   acquired = FALSE;
										   name = r.name;
										   infotext = r.infotext;
									   else
										   update public.locks set datum = current_timestamp, name = name_in, infotext = infotext_in
											   where wert = wert_in;
										   acquired = TRUE;
										   name = name_in;
										   infotext = infotext_in;
									   end if;
									   return;
								   end loop;
								   insert into public.locks (datum, wert, name, infotext) values (current_timestamp, wert_in, name_in, infotext_in);
									   acquired = TRUE;
									   name = name_in;
									   infotext = infotext_in;
							   end;
							   $$;


ALTER FUNCTION public.sv_lock_acquire(wert_in text, name_in text, infotext_in text, OUT acquired boolean, OUT name text, OUT infotext text) OWNER TO adc;

--
-- Name: sv_lock_is_timestamp_alive(timestamp with time zone); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.sv_lock_is_timestamp_alive(timestamp_in timestamp with time zone) RETURNS boolean
    LANGUAGE sql
    AS $_$
								   -- lock_ttl_seconds = 240
								   select age(current_timestamp, $1) < format('%s seconds', 240)::interval
							   $_$;


ALTER FUNCTION public.sv_lock_is_timestamp_alive(timestamp_in timestamp with time zone) OWNER TO adc;

--
-- Name: targetfeiertage(integer, integer); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.targetfeiertage(yearstart integer, yearend integer) RETURNS SETOF date
    LANGUAGE plpgsql
    AS $$ 
			DECLARE
				_eastersunday date;
			BEGIN
				FOR i IN yearStart..yearEnd LOOP
					--Neujahr (1. Januar)
					RETURN NEXT to_date( i || '-' || '01' || '-' || '01', 'yyyy-mm-dd');
					_eastersunday := eastersunday(i);
					-- Karfreitag
					RETURN NEXT _eastersunday - 2;
					-- Ostermontag
					RETURN NEXT _eastersunday + 1;
					-- Tag der Arbeit (1. Mai)
					RETURN NEXT to_date( i || '-' || '05' || '-' || '01', 'yyyy-mm-dd');
					-- Erster und Zweiter Weihnachtsfeiertag (25. und 26. Dezember)
					RETURN NEXT to_date( i || '-' || '12' || '-' || '25', 'yyyy-mm-dd');
					RETURN NEXT to_date( i || '-' || '12' || '-' || '26', 'yyyy-mm-dd');
				END LOOP;
			END
		 $$;


ALTER FUNCTION public.targetfeiertage(yearstart integer, yearend integer) OWNER TO adc;

