CREATE FUNCTION public.update_modified_date() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			BEGIN
				IF OLD != NEW THEN
					NEW.updated_at = now();
				END IF;
				RETURN NEW;
			END;
		 $$;


