--
-- Name: updatebons(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.updatebons() RETURNS SETOF integer
    LANGUAGE plpgsql
    AS $$ DECLARE 	r public.currentbon; BEGIN 	FOR r IN SELECT * FROM public.currentbon WHERE bonnr != 0 ORDER BY id 	LOOP 		IF r.summe-r.ec <> 0 THEN 			INSERT INTO public.currentbon_zahlung(bon_id, zahlungsart, betrag) VALUES( r.id, 1, r.summe-r.ec ); 		END IF; 		IF r.ec <> 0 THEN 			INSERT INTO public.currentbon_zahlung(bon_id, zahlungsart, betrag) VALUES( r.id, 2, r.ec ); 		END IF; 		RETURN NEXT r.id; 	END LOOP; 	RETURN; END $$;


ALTER FUNCTION public.updatebons() OWNER TO adc;

