-- Name: updated_at_rechpos_trigger(); Type: FUNCTION; Schema: public; Owner: adc
--

CREATE FUNCTION public.updated_at_rechpos_trigger() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ 
			BEGIN
				IF (TG_OP = 'DELETE') THEN
					UPDATE public.rechnung SET updated_at = NOW() WHERE id = OLD.rechnung;
				ELSE
					UPDATE public.rechnung SET updated_at = NOW() WHERE id = NEW.rechnung;
				END IF;
				RETURN NULL;
			END
		 $$;


ALTER FUNCTION public.updated_at_rechpos_trigger() OWNER TO adc;

