--
-- Name: filialen_view; Type: VIEW; Schema: public; Owner: adc
--

CREATE VIEW public.filialen_view AS
 WITH zentrale AS (
         SELECT config.id,
            config.param
           FROM public.config
          WHERE (config.id = ANY (ARRAY['iknr'::text, 'firmenname'::text, 'ort'::text, 'firmenstr'::text, 'firmenhausnummer'::text, 'firmenplz'::text, 'firmentel'::text]))
        )
 SELECT 0 AS nummer,
    ( SELECT zentrale.param
           FROM zentrale
          WHERE (zentrale.id = 'iknr'::text)) AS kkinstitut,
    ( SELECT zentrale.param
           FROM zentrale
          WHERE (zentrale.id = 'firmenname'::text)) AS name,
    ( SELECT zentrale.param
           FROM zentrale
          WHERE (zentrale.id = 'firmenstr'::text)) AS strasse,
    ( SELECT zentrale.param
           FROM zentrale
          WHERE (zentrale.id = 'firmenhausnummer'::text)) AS hausnummer,
    public.strasse_mit_hausnummer(( SELECT zentrale.param
           FROM zentrale
          WHERE (zentrale.id = 'firmenstr'::text)), ( SELECT zentrale.param
           FROM zentrale
          WHERE (zentrale.id = 'firmenhausnummer'::text))) AS strasse_hausnummer,
    ( SELECT zentrale.param
           FROM zentrale
          WHERE (zentrale.id = 'ort'::text)) AS ort,
    ( SELECT zentrale.param
           FROM zentrale
          WHERE (zentrale.id = 'firmenplz'::text)) AS plz,
    ( SELECT zentrale.param
           FROM zentrale
          WHERE (zentrale.id = 'firmentel'::text)) AS telefon
UNION ALL
 SELECT filialen.nummer,
    filialen.kkinstitut,
    filialen.name,
    filialen.strasse,
    filialen.hausnummer,
    public.strasse_mit_hausnummer(filialen.strasse, filialen.hausnummer) AS strasse_hausnummer,
    filialen.ort,
    filialen.plz,
    filialen.telefon
   FROM public.filialen;


ALTER TABLE public.filialen_view OWNER TO adc;

