--
-- Name: rechnung_modalitaet_view; Type: VIEW; Schema: public; Owner: adc
--

CREATE VIEW public.rechnung_modalitaet_view AS
 SELECT rechnung_modalitaet.rechnung,
    min(rechnung_modalitaet.beginn) AS beginn,
    NULLIF(max(COALESCE(rechnung_modalitaet.ende, '9999-12-31'::date)), '9999-12-31'::date) AS ende
   FROM public.rechnung_modalitaet
  WHERE (rechnung_modalitaet.deleted_datum IS NULL)
  GROUP BY rechnung_modalitaet.rechnung;


