--
-- Name: refraktion_used_view; Type: VIEW; Schema: public; Owner: adc
--

CREATE VIEW public.refraktion_used_view AS
 SELECT refraktion.id,
    refraktion.kd_id,
    refraktion.refuse,
    refraktion.flags,
    refraktion.sonstiges,
    refraktion.eigen_person AS person,
    refraktion.eigen_subj_datum AS datum,
    refraktion.eigen_subj_bin_visus AS bin_visus,
    refraktion.eigen_subj_re_sph AS re_sph,
    refraktion.eigen_subj_re_cyl AS re_cyl,
    refraktion.eigen_subj_re_a AS re_a,
    refraktion.eigen_subj_re_add AS re_add,
    refraktion.eigen_subj_re_pr_horiz AS re_pr_horiz,
    refraktion.eigen_subj_re_pr_vert AS re_pr_vert,
    refraktion.eigen_subj_re_ba_horiz AS re_ba_horiz,
    refraktion.eigen_subj_re_ba_vert AS re_ba_vert,
    refraktion.eigen_subj_re_hsa AS re_hsa,
    refraktion.eigen_subj_re_visus AS re_visus,
    refraktion.eigen_subj_re_ma AS re_ma,
    refraktion.eigen_subj_re_v_sc AS re_v_sc,
    refraktion.eigen_subj_li_sph AS li_sph,
    refraktion.eigen_subj_li_cyl AS li_cyl,
    refraktion.eigen_subj_li_a AS li_a,
    refraktion.eigen_subj_li_add AS li_add,
    refraktion.eigen_subj_li_pr_horiz AS li_pr_horiz,
    refraktion.eigen_subj_li_pr_vert AS li_pr_vert,
    refraktion.eigen_subj_li_ba_horiz AS li_ba_horiz,
    refraktion.eigen_subj_li_ba_vert AS li_ba_vert,
    refraktion.eigen_subj_li_hsa AS li_hsa,
    refraktion.eigen_subj_li_visus AS li_visus,
    refraktion.eigen_subj_li_ma AS li_ma,
    refraktion.eigen_subj_li_v_sc AS li_v_sc,
    refraktion.eigen_seh_art AS seh_art,
    refraktion.eigen_seh_glas AS seh_glas,
    refraktion.bemerkung,
    refraktion.eigen_seh_fuehrungsauge AS seh_fuehrungsauge,
    refraktion.eigen_leseabstand AS leseabstand,
    refraktion.is_online
   FROM public.refraktion
  WHERE (refraktion.refuse = 1)
UNION ALL
 SELECT refraktion.id,
    refraktion.kd_id,
    refraktion.refuse,
    refraktion.flags,
    refraktion.sonstiges,
    refraktion.fremd_person AS person,
    refraktion.fremd_datum AS datum,
    refraktion.fremd_bin_visus AS bin_visus,
    refraktion.fremd_re_sph AS re_sph,
    refraktion.fremd_re_cyl AS re_cyl,
    refraktion.fremd_re_a AS re_a,
    refraktion.fremd_re_add AS re_add,
    refraktion.fremd_re_pr_horiz AS re_pr_horiz,
    refraktion.fremd_re_pr_vert AS re_pr_vert,
    refraktion.fremd_re_ba_horiz AS re_ba_horiz,
    refraktion.fremd_re_ba_vert AS re_ba_vert,
    refraktion.fremd_re_hsa AS re_hsa,
    refraktion.fremd_re_visus AS re_visus,
    refraktion.fremd_re_ma AS re_ma,
    refraktion.fremd_re_v_sc AS re_v_sc,
    refraktion.fremd_li_sph AS li_sph,
    refraktion.fremd_li_cyl AS li_cyl,
    refraktion.fremd_li_a AS li_a,
    refraktion.fremd_li_add AS li_add,
    refraktion.fremd_li_pr_horiz AS li_pr_horiz,
    refraktion.fremd_li_pr_vert AS li_pr_vert,
    refraktion.fremd_li_ba_horiz AS li_ba_horiz,
    refraktion.fremd_li_ba_vert AS li_ba_vert,
    refraktion.fremd_li_hsa AS li_hsa,
    refraktion.fremd_li_visus AS li_visus,
    refraktion.fremd_li_ma AS li_ma,
    refraktion.fremd_li_v_sc AS li_v_sc,
    refraktion.fremd_seh_art AS seh_art,
    refraktion.fremd_seh_glas AS seh_glas,
    refraktion.bemerkung,
    refraktion.fremd_seh_fuehrungsauge AS seh_fuehrungsauge,
    refraktion.fremd_leseabstand AS leseabstand,
    refraktion.is_online
   FROM public.refraktion
  WHERE (refraktion.refuse = 2);


