--
-- Name: v_rm_pw_statuses; Type: VIEW; Schema: public; Owner: adc
--

CREATE VIEW public.v_rm_pw_statuses AS
 SELECT pers.id AS user_id,
        CASE
            WHEN (pws.user_id IS NULL) THEN 1
            WHEN (pws.md5_hash IS NULL) THEN 2
            WHEN (pws.expires_ts < now()) THEN 3
            WHEN (pws.warn_ts < now()) THEN 5
            ELSE 4
        END AS pw_status,
    pws.single_use AS pw_single_use,
    pws.expires_ts,
    pws.warn_ts
   FROM (public.personen pers
     LEFT JOIN public.rm_user_pw pws ON ((pws.user_id = pers.id)))
  WHERE (((pers.typ & 2) > 0) AND (pers.id > '-1'::integer));


ALTER TABLE public.v_rm_pw_statuses OWNER TO adc;

--
-- Name: v_rm_pw_statusesactiveonly; Type: VIEW; Schema: public; Owner: adc
--

CREATE VIEW public.v_rm_pw_statusesactiveonly AS
 SELECT stat.user_id,
    stat.pw_status,
    stat.pw_single_use,
    stat.expires_ts,
    stat.warn_ts
   FROM (public.v_rm_pw_statuses stat
     JOIN public.personen pers ON ((pers.id = stat.user_id)))
  WHERE ((pers.flags & 16) = 16);


ALTER TABLE public.v_rm_pw_statusesactiveonly OWNER TO adc;

--
-- Name: v_rm_roles_for_users; Type: VIEW; Schema: public; Owner: adc
