--
-- Name: vsauftragkkanteil; Type: TABLE; Schema: public; Owner: adc
--

CREATE TABLE public.vsauftragkkanteil (
    id integer NOT NULL,
    vsauftragid integer NOT NULL,
    kkanteilid integer NOT NULL,
    vsteileid integer,
    betrag numeric(12,2) NOT NULL,
    kennzeichen integer,
    netto boolean DEFAULT false NOT NULL,
    mwst_typ integer DEFAULT 0 NOT NULL,
    egeko_position_id integer,
    poolnummer text,
    versorgung_von date,
    versorgung_bis date
);


ALTER TABLE public.vsauftragkkanteil OWNER TO adc;

--
-- Name: vsauftragkkanteil_brutto_view; Type: VIEW; Schema: public; Owner: adc
--

CREATE VIEW public.vsauftragkkanteil_brutto_view AS
 SELECT kk.id,
    kk.vsauftragid,
    kk.kkanteilid,
    kk.vsteileid,
    kk.betrag,
    kk.kennzeichen,
    kk.netto,
    kk.mwst_typ,
    kk.egeko_position_id,
    kk.poolnummer,
    kk.versorgung_von,
    kk.versorgung_bis,
        CASE
            WHEN kk.netto THEN
            CASE
                WHEN (kk.mwst_typ = 0) THEN round(((public.numericempty(kk.betrag) * ((100)::numeric + v.mwstsatz0)) / (100)::numeric), 2)
                WHEN (kk.mwst_typ = 1) THEN round(((public.numericempty(kk.betrag) * ((100)::numeric + v.mwstsatz1)) / (100)::numeric), 2)
                ELSE public.numericempty(kk.betrag)
            END
            ELSE public.numericempty(kk.betrag)
        END AS betrag_brutto
   FROM (public.vsauftragkkanteil kk
     JOIN public.vsauftrag v ON ((v.id = kk.vsauftragid)));


ALTER TABLE public.vsauftragkkanteil_brutto_view OWNER TO adc;

--
-- Name: vsauftragkkanteil_id_seq; Type: SEQUENCE; Schema: public; Owner: adc
