-- Name: vsauftragkkanteil_id_seq; Type: SEQUENCE OWNED BY; Schema: public; Owner: adc
--

ALTER SEQUENCE public.vsauftragkkanteil_id_seq OWNED BY public.vsauftragkkanteil.id;


--
-- Name: vsauftragkkanteil_view; Type: VIEW; Schema: public; Owner: adc
--

CREATE VIEW public.vsauftragkkanteil_view AS
 SELECT a.id,
    a.vsauftragid,
    a.kkanteilid,
    a.vsteileid,
    k.nr,
    (a.betrag)::double precision AS betrag,
    k.beschr,
    COALESCE(a.kennzeichen, 0) AS kennzeichen,
    a.netto,
    a.mwst_typ,
    a.egeko_position_id,
    a.poolnummer,
    NULL::text AS egeko_position_link_temp,
    a.versorgung_von,
    a.versorgung_bis
   FROM (public.vsauftragkkanteil a
     JOIN public.kkanteil k ON ((a.kkanteilid = k.id)));


ALTER TABLE public.vsauftragkkanteil_view OWNER TO adc;

