--
-- Name: vsauftragkkanteil_view add; Type: RULE; Schema: public; Owner: adc
--

CREATE RULE add AS
    ON INSERT TO public.vsauftragkkanteil_view DO INSTEAD  INSERT INTO public.vsauftragkkanteil (id, vsauftragid, kkanteilid, vsteileid, betrag, kennzeichen, netto, mwst_typ, egeko_position_id, poolnummer, versorgung_von, versorgung_bis)
  VALUES (new.id, new.vsauftragid, new.kkanteilid, new.vsteileid, new.betrag, new.kennzeichen, new.netto, new.mwst_typ, new.egeko_position_id, new.poolnummer, new.versorgung_von, new.versorgung_bis);


--
-- Name: vsauftragkkanteil_view edit; Type: RULE; Schema: public; Owner: adc
--

CREATE RULE edit AS
    ON UPDATE TO public.vsauftragkkanteil_view DO INSTEAD  UPDATE public.vsauftragkkanteil SET id = new.id, vsauftragid = new.vsauftragid, kkanteilid = new.kkanteilid, vsteileid = new.vsteileid, betrag = new.betrag, kennzeichen = new.kennzeichen, netto = new.netto, mwst_typ = new.mwst_typ, egeko_position_id = new.egeko_position_id, poolnummer = new.poolnummer, versorgung_von = new.versorgung_von, versorgung_bis = new.versorgung_bis
  WHERE (vsauftragkkanteil.id = old.id);


--
-- Name: vsauftragkkanteil_view remove; Type: RULE; Schema: public; Owner: adc
--

CREATE RULE remove AS
    ON DELETE TO public.vsauftragkkanteil_view DO INSTEAD  DELETE FROM public.vsauftragkkanteil
  WHERE (vsauftragkkanteil.id = old.id);


--
-- Name: rm_userroles rule_delete_sets_inactive; Type: RULE; Schema: public; Owner: adc
--

CREATE RULE rule_delete_sets_inactive AS
    ON DELETE TO public.rm_userroles DO INSTEAD  UPDATE public.rm_userroles SET active = false
  WHERE (rm_userroles.id = old.id);


