--

CREATE TRIGGER audit_trigger_row AFTER INSERT OR DELETE OR UPDATE ON public.abrechnung FOR EACH ROW WHEN ((public.sv_current_setting('softwarevision.disableaudit'::text, 'false'::text) = 'false'::text)) EXECUTE PROCEDURE audit.if_modified_func('true', '', '', 'WITH tmp AS ( SELECT %s AS id ) SELECT 1 FROM public.rechnung_pos_kkabrechnung p INNER JOIN public.rechnung r ON r.id = p.rechnung WHERE p.abrechnung = (SELECT id FROM tmp) AND r.rechnung_nr IS NOT NULL AND r.deleted_datum IS NULL AND p.deleted_datum IS NULL UNION SELECT 2 FROM public.rechnung_modalitaet m INNER JOIN public.rechnung r ON m.rechnung = r.id WHERE m.kk_abrechnung = (SELECT id FROM tmp) AND r.deleted_datum IS NULL AND m.deleted_datum IS NULL', 'id');


