--
-- Name: cl_linse_detail audit_trigger_row; Type: TRIGGER; Schema: public; Owner: adc
--

CREATE TRIGGER audit_trigger_row AFTER INSERT OR DELETE OR UPDATE ON public.cl_linse_detail FOR EACH ROW WHEN ((public.sv_current_setting('softwarevision.disableaudit'::text, 'false'::text) = 'false'::text)) EXECUTE PROCEDURE audit.if_modified_func('true', '', '', 'WITH tmp AS ( SELECT id FROM cl_linse WHERE %s IN (linse_rechts, linse_links) ) SELECT 1 FROM public.rechnung_pos_linsen l INNER JOIN public.rechnung r ON l.rechnung = r.id WHERE l.linse IN (SELECT id FROM tmp) AND r.rechnung_nr IS NOT NULL AND r.deleted_datum IS NULL AND l.deleted_datum IS NULL UNION SELECT 2 FROM public.rechnung_pos_linsen l INNER JOIN public.abos a ON a.rechnung = l.rechnung INNER JOIN public.rechnung r ON l.rechnung = r.id WHERE l.linse IN (SELECT id FROM tmp) AND a.status != 0 AND r.deleted_datum IS NULL AND l.deleted_datum IS NULL LIMIT 1', 'id');


--
-- Name: cl_linse audit_trigger_row; Type: TRIGGER; Schema: public; Owner: adc
--

